import { supabase } from './supabase';
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, Style, StyleTemplate } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- Style Database Services ---
export const fetchStyles = async (): Promise<Style[]> => {
  const { data, error } = await supabase.from('styles').select('*').order('style_number', { ascending: true });
  if (error || !data) return [];
  return data as Style[];
};

export const fetchStyleByNumber = async (styleNum: string): Promise<Style | null> => {
    const { data, error } = await supabase.from('styles').select('*').eq('style_number', styleNum).maybeSingle();
    if (error || !data) return null;
    return data as Style;
};

export const fetchStyleById = async (id: string): Promise<Style | null> => {
    const { data, error } = await supabase.from('styles').select('*').eq('id', id).single();
    if (error || !data) return null;
    return data as Style;
};

export const upsertStyle = async (style: Partial<Style>): Promise<{ data: Style | null, error: string | null }> => {
  const { data, error } = await supabase.from('styles').upsert([style]).select().single();
  if (error) return { data: null, error: error.message };
  return { data: data as Style, error: null };
};

export const deleteStyle = async (id: string): Promise<void> => {
  await supabase.from('styles').delete().eq('id', id);
};

export const fetchStyleTemplate = async (): Promise<StyleTemplate | null> => {
  const { data, error } = await supabase.from('style_templates').select('*').eq('id', 1).single();
  if (error || !data) return null;
  return data as StyleTemplate;
};

export const updateStyleTemplate = async (config: any[]): Promise<void> => {
  await supabase.from('style_templates').upsert([{ id: 1, config, updated_at: new Date().toISOString() }]);
};
// --- End Style Database Services ---

export const triggerOrderEmail = async (orderId: string, isEdit: boolean = false): Promise<{ success: boolean; message: string }> => {
  try {
    const response = await fetch(`${API_BASE}/api/send-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ order_id: orderId, is_edit: isEdit })
    });
    const result = await response.json();
    return { success: response.ok, message: result.message };
  } catch (error) {
    return { success: false, message: 'Network error triggering email.' };
  }
};

export const triggerMaterialEmail = async (orderId: string): Promise<{ success: boolean; message: string }> => {
  try {
    const response = await fetch(`${API_BASE}/api/send-material-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ order_id: orderId })
    });
    const result = await response.json();
    return { success: response.ok, message: result.message };
  } catch (error) {
    return { success: false, message: 'Network error triggering material email.' };
  }
};

export const authenticateUser = async (username: string, password: string): Promise<AppUser | null> => {
    const { data, error } = await supabase.from('app_users').select('*').eq('username', username).eq('password', password).single();
    if (error || !data) return null;
    return { id: data.id, username: data.username, role: data.role as UserRole, full_name: data.full_name };
};

export const fetchOrderLogs = async (orderId?: string): Promise<OrderLog[]> => {
    let query = supabase.from('order_logs').select('*').order('created_at', { ascending: false });
    if (orderId) query = query.eq('order_id', orderId);
    const { data, error } = await query;
    if (error || !data) return [];
    return data as OrderLog[];
};

export const addOrderLog = async (orderId: string, type: 'STATUS_CHANGE' | 'MANUAL_UPDATE' | 'CREATION', message: string) => {
    await supabase.from('order_logs').insert([{ order_id: orderId, log_type: type, message: message, created_by_name: 'System' }]);
};

export const fetchUnits = async (): Promise<Unit[]> => {
    const { data, error } = await supabase.from('units').select('*').order('id');
    if (error || !data) return [];
    return data as Unit[];
};

export const fetchOrders = async (): Promise<Order[]> => {
  const { data, error } = await supabase.from('orders').select('*').or('deleted.eq.false,deleted.is.null').order('created_at', { ascending: false });
  if (error || !data) return [];
  return data as Order[];
};

export const syncAllOrdersWithStyles = async (): Promise<{ updated: number; total: number }> => {
  const orders = await fetchOrders();
  const styles = await fetchStyles();
  let updatedCount = 0;

  for (const order of orders) {
    // Determine the base style number prefix (before the hyphen)
    const stylePrefix = order.style_number.split(' - ')[0].trim();
    const match = styles.find(s => s.style_number.trim().toLowerCase() === stylePrefix.toLowerCase());

    if (match) {
      const canonicalStyleName = `${match.style_number} - ${match.style_text}`;
      const canonicalSizeFormat = match.size_type === 'number' ? 'numeric' : 'standard';

      // Check if order data differs from latest DB technical definitions
      if (order.style_number !== canonicalStyleName || order.size_format !== canonicalSizeFormat) {
        const { error } = await supabase.from('orders').update({
          style_number: canonicalStyleName,
          size_format: canonicalSizeFormat
        }).eq('id', order.id);

        if (!error) {
          updatedCount++;
          await addOrderLog(order.id, 'MANUAL_UPDATE', `Sync: Order metadata updated from Style DB technical entry.`);
        }
      }
    }
  }

  return { updated: updatedCount, total: orders.length };
};

export const createOrder = async (order: Partial<Order>): Promise<{ data: Order | null, error: string | null }> => {
    const { data: seqValue, error: seqError } = await supabase.rpc('next_order_no');
    if (seqError || !seqValue) return { data: null, error: 'Failed to generate order number' };
    const orderNo = `ORD-${seqValue}`;
    const payload: any = {
        order_no: orderNo,
        unit_id: order.unit_id,
        style_number: order.style_number,
        quantity: order.quantity,
        size_breakdown: order.size_breakdown,
        description: order.description,
        target_delivery_date: order.target_delivery_date,
        status: OrderStatus.ASSIGNED,
        deleted: false
    };
    const optionalKeys: (keyof Order)[] = ['box_count', 'size_format', 'attachments'];
    optionalKeys.forEach(key => { if (order[key] !== undefined) payload[key] = order[key]; });
    const { data, error } = await supabase.from('orders').insert([payload]).select().single();
    if (error) return { data: null, error: error.message };
    if (data) await addOrderLog(data.id, 'CREATION', `Order #${orderNo} Launched.`);
    return { data: data as Order, error: null };
};

export const deleteOrder = async (orderId: string): Promise<void> => {
    await supabase.from('orders').update({ deleted: true }).eq('id', orderId);
};

export const updateOrderStatus = async (orderId: string, status: OrderStatus, notes?: string, completionData?: any, qcAttachmentUrl?: string): Promise<void> => {
   const payload: any = { status, qc_notes: notes };
   if (completionData) {
       payload.completion_breakdown = completionData.completion_breakdown;
       payload.actual_box_count = completionData.actual_box_count;
   }
   if (qcAttachmentUrl) payload.qc_attachment_url = qcAttachmentUrl;
   await supabase.from('orders').update(payload).eq('id', orderId);
   await addOrderLog(orderId, 'STATUS_CHANGE', `Status: ${status}${notes ? ` - ${notes}` : ''}`);
};

export const updateOrderDetails = async (orderId: string, updates: Partial<Order>): Promise<{ success: boolean; error: string | null }> => {
    const payload: any = {};
    const allowedKeys = ['style_number', 'unit_id', 'quantity', 'description', 'target_delivery_date', 'size_breakdown', 'size_format', 'attachments', 'box_count'];
    allowedKeys.forEach(k => { if ((updates as any)[k] !== undefined) payload[k] = (updates as any)[k]; });
    const { error } = await supabase.from('orders').update(payload).eq('id', orderId);
    if (error) return { success: false, error: error.message };
    await addOrderLog(orderId, 'MANUAL_UPDATE', 'Order details revised by Admin.');
    return { success: true, error: null };
};

export const fetchMaterialRequests = async (): Promise<MaterialRequest[]> => {
    const { data, error } = await supabase.from('material_requests').select('*').order('created_at', { ascending: false });
    if (error || !data) return [];
    return data as MaterialRequest[];
};

export const createMaterialRequest = async (req: Partial<MaterialRequest>) => {
    await supabase.from('material_requests').insert([{
        order_id: req.order_id,
        material_content: req.material_content,
        quantity_requested: req.quantity_requested,
        unit: req.unit || 'Nos',
        attachments: req.attachments || [], 
        status: MaterialStatus.PENDING
    }]);
};

export const updateMaterialRequest = async (id: string, updates: Partial<MaterialRequest>) => {
    await supabase.from('material_requests').update(updates).eq('id', id);
};

export const deleteMaterialRequest = async (id: string) => {
    await supabase.from('material_requests').delete().eq('id', id);
};

export const fetchMaterialApprovals = async (requestId: string): Promise<MaterialApproval[]> => {
    const { data, error } = await supabase.from('material_approvals').select('*').eq('request_id', requestId).order('created_at', { ascending: true });
    if (error || !data) return [];
    return data as MaterialApproval[];
};

export const approveMaterialRequest = async (id: string, qtyApprovedNow: number, currentTotalApproved: number, newStatus: MaterialStatus) => {
    await supabase.from('material_approvals').insert([{ request_id: id, qty_approved: qtyApprovedNow, approved_by_name: 'Materials Dept' }]);
    await supabase.from('material_requests').update({ quantity_approved: currentTotalApproved + qtyApprovedNow, status: newStatus }).eq('id', id);
};

export const fetchBarcodes = async (statusFilter?: BarcodeStatus): Promise<Barcode[]> => {
    let query = supabase.from('barcodes').select('*');
    if (statusFilter) query = query.eq('status', statusFilter);
    const { data, error } = await query;
    if (error || !data) return [];
    return data as Barcode[];
};

export const fetchBarcodesBySerialList = async (serials: string[]): Promise<Barcode[]> => {
    if (serials.length === 0) return [];
    const { data, error } = await supabase.from('barcodes').select('*').in('barcode_serial', serials);
    if (error || !data) return [];
    return data as Barcode[];
};

export const generateBarcodes = async (orderId: string, count: number, style: string, size: string) => {
    const orderRes = await supabase.from('orders').select('order_no, last_barcode_serial').eq('id', orderId).single();
    if (orderRes.error || !orderRes.data) return [];
    let currentSerial = orderRes.data.last_barcode_serial || 0;
    const newBarcodes = [];
    for (let i = 1; i <= count; i++) {
        currentSerial++;
        newBarcodes.push({
            barcode_serial: `${orderRes.data.order_no};${style};${size};${currentSerial.toString().padStart(5, '0')}`,
            order_id: orderId, style_number: style, size: size, status: BarcodeStatus.GENERATED
        });
    }
    await supabase.from('barcodes').insert(newBarcodes);
    await supabase.from('orders').update({ last_barcode_serial: currentSerial }).eq('id', orderId);
    return newBarcodes as any[];
};

export const commitBarcodesToStock = async (serials: string[]) => {
    const { data: commitData, error: commitError } = await supabase.from('stock_commits').insert([{ total_items: serials.length }]).select().single();
    if (commitError) return;
    await supabase.from('barcodes').update({ status: BarcodeStatus.COMMITTED_TO_STOCK, commit_id: commitData.id }).in('barcode_serial', serials);
};

export const fetchStockCommits = async (): Promise<StockCommit[]> => {
    const { data, error } = await supabase.from('stock_commits').select('*').order('created_at', { ascending: false });
    if (error || !data) return [];
    return data as StockCommit[];
};

export const fetchBarcodesByCommit = async (commitId: number): Promise<Barcode[]> => {
    const { data, error } = await supabase.from('barcodes').select('*').eq('commit_id', commitId);
    if (error || !data) return [];
    return data as Barcode[];
};

export const fetchInvoices = async (): Promise<Invoice[]> => {
    const { data, error } = await supabase.from('invoices').select('*').order('created_at', { ascending: false });
    if (error || !data) return [];
    return data as Invoice[];
};

export const fetchInvoiceItems = async (invoiceId: string): Promise<Barcode[]> => {
    const { data, error } = await supabase.from('barcodes').select('*').eq('invoice_id', invoiceId);
    if (error || !data) return [];
    return data as Barcode[];
}

export const createInvoice = async (customerName: string, barcodeIds: string[], customInvoiceNo?: string): Promise<Invoice> => {
    const invoiceNo = customInvoiceNo || `INV-${Date.now()}`;
    const { data: invData, error: invError } = await supabase.from('invoices').insert([{ invoice_no: invoiceNo, customer_name: customerName, total_amount: barcodeIds.length * 25.00 }]).select().single();
    if (invError) throw invError;
    await supabase.from('barcodes').update({ status: BarcodeStatus.SOLD, invoice_id: invData.id }).in('id', barcodeIds);
    return invData as Invoice;
};

export const uploadOrderAttachment = async (file: File): Promise<string | null> => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
    const { error } = await supabase.storage.from('order-attachments').upload(fileName, file);
    if (error) return null;
    const { data } = supabase.storage.from('order-attachments').getPublicUrl(fileName);
    return data.publicUrl;
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, fetchUnits, fetchBarcodes, triggerOrderEmail, fetchOrderLogs, syncAllOrdersWithStyles } from '../services/db';
import { Order, Unit, OrderStatus, BarcodeStatus, formatOrderNumber, OrderLog } from '../types';
import { BarChart3, PieChart, PlusCircle, ClipboardList, Printer, Loader2, RefreshCcw, Database } from 'lucide-react';
import { DashboardStats } from '../components/admin/DashboardStats';
import { MasterOrderList } from '../components/admin/MasterOrderList';
import { LaunchOrderModal } from '../components/admin/LaunchOrderModal';
import { AdminOrderDetailsModal } from '../components/admin/AdminOrderDetailsModal';

export const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'reports'>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
  const [liveStockCount, setLiveStockCount] = useState(0);
  const [activeOrderCount, setActiveOrderCount] = useState(0);
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [isLaunchModalOpen, setIsLaunchModalOpen] = useState(false);
  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [reportLoading, setReportLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const loadData = async () => {
    const [fetchedOrders, fetchedUnits, fetchedStock] = await Promise.all([
        fetchOrders(), 
        fetchUnits(),
        fetchBarcodes(BarcodeStatus.COMMITTED_TO_STOCK)
    ]);
    setOrders(fetchedOrders);
    setUnits(fetchedUnits);
    setLiveStockCount(fetchedStock.length);
    setActiveOrderCount(fetchedOrders.filter(o => o.status !== OrderStatus.COMPLETED).length);
  };

  useEffect(() => { loadData(); }, [activeTab]);

  const handleGlobalSync = async () => {
    if (!confirm("This will refresh the material forecast links for all existing orders based on the latest Style DB technical specs. Continue?")) return;
    setIsSyncing(true);
    try {
      const result = await syncAllOrdersWithStyles();
      alert(`Sync Complete: Successfully updated technical forecast links for ${result.updated} out of ${result.total} orders.`);
      await loadData();
    } catch (err) {
      alert("Error during global sync: " + err);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleSendEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerOrderEmail(orderId, false);
    setEmailLoading(null);
    alert(result.message);
  };

  const handlePrintUnitReport = async () => {
    setReportLoading(true);
    try {
      const inProgressOrders = orders.filter(o => o.status === OrderStatus.IN_PROGRESS);
      const assignedOrders = orders.filter(o => o.status === OrderStatus.ASSIGNED);

      const allLogs = await fetchOrderLogs();
      const inProgressOrderIds = inProgressOrders.map(o => o.id);

      // Filter logs for in-progress orders, sort by date descending, and take the last 5
      const recentLogs = allLogs
        .filter(log => inProgressOrderIds.includes(log.order_id))
        .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 5);

      // Group these top 5 logs by order_id
      const groupedLogs: Record<string, OrderLog[]> = {};
      recentLogs.forEach(log => {
        if (!groupedLogs[log.order_id]) groupedLogs[log.order_id] = [];
        groupedLogs[log.order_id].push(log);
      });

      const win = window.open('', 'UnitReport', 'width=1000,height=800');
      if (win) {
        const logSectionsHtml = Object.entries(groupedLogs).map(([orderId, logs]) => {
          const order = inProgressOrders.find(o => o.id === orderId);
          const orderRef = order ? formatOrderNumber(order) : 'UNK';

          return `
            <div style="margin-bottom: 20px; border: 1.5px solid #1e293b; border-radius: 8px; overflow: hidden; page-break-inside: avoid;">
              <div style="background: #1e293b; padding: 10px 15px; font-weight: 900; color: #fff; font-size: 13px; text-transform: uppercase;">
                Job Ref: ${orderRef}
              </div>
              <table style="width: 100%; border-collapse: collapse; background: #fff;">
                <tbody style="font-size: 11px;">
                  ${logs.map(log => `
                    <tr style="border-bottom: 1px solid #e2e8f0;">
                      <td style="padding: 10px; width: 160px; color: #64748b; font-weight: bold; border-right: 1px solid #e2e8f0;">${new Date(log.created_at).toLocaleString()}</td>
                      <td style="padding: 10px; color: #1e293b; font-weight: 500;">${log.message}</td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `;
        }).join('');

        const assignedRows = assignedOrders.map(order => `
          <tr>
            <td style="padding: 10px; border: 1px solid #ddd; font-weight: bold;">${formatOrderNumber(order)}</td>
            <td style="padding: 10px; border: 1px solid #ddd;">${order.style_number}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center; font-weight: bold;">${order.quantity}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center;">${order.target_delivery_date}</td>
          </tr>
        `).join('');

        win.document.write(`
          <html>
          <head>
            <title>Unit Production Report</title>
            <style>
              body { font-family: sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; background: #fff; }
              .header { border-bottom: 4px solid #000; padding-bottom: 20px; margin-bottom: 30px; text-align: center; }
              .brand { font-size: 28px; font-weight: 900; letter-spacing: 1px; }
              .title { font-size: 16px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-top: 5px; }
              .section-title { font-size: 14px; font-weight: 900; background: #f1f5f9; padding: 10px 15px; border-left: 6px solid #1e293b; margin: 40px 0 20px 0; text-transform: uppercase; letter-spacing: 1px; }
              table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; }
              th { background: #f8fafc; text-align: left; padding: 12px; border: 1px solid #ddd; text-transform: uppercase; font-size: 10px; color: #64748b; }
              .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #eee; padding-top: 20px; }
              @media print { body { padding: 20px; } .section-title { -webkit-print-color-adjust: exact; } }
            </style>
          </head>
          <body>
            <div class="header">
              <div class="brand">TINTURA SST</div>
              <div class="title">Manufacturing Unit Executive Report</div>
              <div style="font-size: 11px; margin-top: 10px; font-weight: bold; color: #94a3b8;">DISPATCHED: ${new Date().toLocaleString()}</div>
            </div>

            <div class="section-title">Recent Timeline Activity (Last 5 Global Updates)</div>
            ${recentLogs.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">No recent floor activity logs recorded for in-progress jobs.</p>' : logSectionsHtml}

            <div class="section-title">Queue Status (Assigned & Unstarted Jobs)</div>
            ${assignedOrders.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">Assigned queue is currently empty.</p>' : `
            <table>
              <thead>
                <tr>
                  <th width="150">Order Ref</th>
                  <th>Style Reference</th>
                  <th width="100" style="text-align: center;">Batch Vol</th>
                  <th width="120" style="text-align: center;">Target Date</th>
                </tr>
              </thead>
              <tbody>${assignedRows}</tbody>
            </table>
            `}

            <div class="footer">
              This report is generated automatically by Tintura SST HQ. 
              <br/>For internal manufacturing supervision only.
            </div>
            <script>window.onload = () => { setTimeout(() => { window.print(); }, 500); };</script>
          </body>
          </html>
        `);
        win.document.close();
      }
    } catch (err) {
      console.error(err);
      alert("Critical: Failed to compile unit report.");
    } finally {
      setReportLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">
          {activeTab === 'overview' ? 'Executive Dashboard' : 'Analytics & Reports'}
        </h2>
        <div className="flex items-center gap-2">
            <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('overview')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'overview' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><BarChart3 size={18}/> Overview</button>
                <button onClick={() => setActiveTab('reports')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><PieChart size={18}/> Reports</button>
            </div>
            {activeTab === 'overview' && (
                <div className="flex gap-2">
                  <button 
                    onClick={handleGlobalSync} 
                    disabled={isSyncing}
                    className="bg-white border-2 border-slate-200 text-slate-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-slate-50 shadow-md transition-all active:scale-95 disabled:opacity-50"
                    title="Refresh all order links with Style Database entries"
                  >
                    {isSyncing ? <Loader2 size={20} className="animate-spin" /> : <RefreshCcw size={20} className="text-indigo-600" />}
                    <span className="font-bold text-sm">Sync Forecasts</span>
                  </button>
                  <button 
                    onClick={handlePrintUnitReport} 
                    disabled={reportLoading}
                    className="bg-white border-2 border-indigo-600 text-indigo-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-50 shadow-md transition-all active:scale-95 disabled:opacity-50"
                  >
                    {reportLoading ? <Loader2 size={20} className="animate-spin" /> : <ClipboardList size={20} />}
                    <span className="font-bold text-sm">Unit Report</span>
                  </button>
                  <button onClick={() => setIsLaunchModalOpen(true)} className="bg-indigo-600 text-white px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95">
                    <PlusCircle size={20} /><span className="font-bold text-sm">Launch New Order</span>
                  </button>
                </div>
            )}
        </div>
      </div>

      {activeTab === 'overview' ? (
        <div className="space-y-6 animate-fade-in">
            <DashboardStats liveStockCount={liveStockCount} activeOrderCount={activeOrderCount} />
            <MasterOrderList 
              orders={orders} 
              units={units} 
              onRefresh={loadData} 
              onViewDetails={setDetailsModal} 
              onSendEmail={handleSendEmail} 
              emailLoading={emailLoading}
            />
        </div>
      ) : (
        <div className="bg-white p-20 rounded-2xl border border-slate-200 text-center text-slate-400 animate-fade-in">
           <PieChart size={48} className="mx-auto mb-4 opacity-20"/>
           <p className="text-lg font-bold">Reporting Suite</p>
           <p className="text-sm">Detailed production analytics and performance KPIs are currently being compiled.</p>
        </div>
      )}

      <LaunchOrderModal 
        isOpen={isLaunchModalOpen} 
        onClose={() => setIsLaunchModalOpen(false)} 
        units={units} 
        onSuccess={loadData} 
      />

      {detailsModal && (
        <AdminOrderDetailsModal 
          order={detailsModal} 
          units={units} 
          onClose={() => setDetailsModal(null)} 
          onRefresh={loadData} 
        />
      )}
    </div>
  );
};

