export const recordBulkEditHistory = async (description: string, stylesToSnapshot: Style[]): Promise<void> => {
  const snapshot: Record<string, Style> = {};
  stylesToSnapshot.forEach(s => {
    snapshot[s.id] = s;
  });

  const historyEntry = {
    description,
    affected_count: stylesToSnapshot.length,
    snapshot
  };

  await supabase.from('bulk_edit_history').insert([historyEntry]);
};

export const fetchBulkEditHistory = async (): Promise<BulkEditHistory[]> => {
  const { data, error } = await supabase
    .from('bulk_edit_history')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(50);

  if (error || !data) return [];
  return data as BulkEditHistory[];
};

export const undoBulkEdit = async (historyId: string): Promise<{ success: boolean; error?: string }> => {
  const { data: history, error: fetchError } = await supabase
    .from('bulk_edit_history')
    .select('*')
    .eq('id', historyId)
    .single();

  if (fetchError || !history) return { success: false, error: 'History record not found' };

  const snapshot = history.snapshot as Record<string, Style>;
  const styleObjects = Object.values(snapshot);

  try {
    for (const style of styleObjects) {
      await supabase.from('styles').upsert([style]);
    }
    // Delete this history entry once undone to prevent logical circularity 
    // (or we could mark it as "Undone")
    await supabase.from('bulk_edit_history').delete().eq('id', historyId);
    return { success: true };
  } catch (err: any) {
    return { success: false, error: err.message };
  }
};

