export const getNextOrderStatus = (current: OrderStatus): OrderStatus | null => {
  switch (current) {
    case OrderStatus.ASSIGNED: return OrderStatus.IN_PROGRESS;
    case OrderStatus.IN_PROGRESS: return OrderStatus.QC;
    case OrderStatus.QC: return OrderStatus.QC_APPROVED;
    case OrderStatus.QC_APPROVED: return OrderStatus.COMPLETED; 
    case OrderStatus.PACKED: return OrderStatus.COMPLETED;
    default: return null;
  }
};

export const getNextBarcodeStatus = (current: BarcodeStatus): BarcodeStatus | null => {
  switch (current) {
    case BarcodeStatus.GENERATED: return BarcodeStatus.DETAILS_FILLED;
    case BarcodeStatus.DETAILS_FILLED: return BarcodeStatus.PUSHED_OUT_OF_SUBUNIT;
    case BarcodeStatus.PUSHED_OUT_OF_SUBUNIT: return BarcodeStatus.QC_APPROVED;
    case BarcodeStatus.QC_APPROVED: return BarcodeStatus.COMMITTED_TO_STOCK;
    case BarcodeStatus.COMMITTED_TO_STOCK: return BarcodeStatus.SOLD;
    default: return null;
  }
};

export const formatOrderNumber = (order: Partial<Order>): string => {
  if (!order.order_no) return 'ORD-NEW';
  const numericMatch = order.order_no.match(/ORD-(\d+)/);
  const serial = numericMatch ? numericMatch[1] : order.order_no;
  const stylePart = order.style_number 
    ? order.style_number.split('-')[0].trim() 
    : 'STYLE';
  return `ORD-${stylePart}-${serial}`;
};

import { supabase } from './supabase';
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, Style, StyleTemplate, BulkEditHistory } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- Style Database Services ---
export const fetchStyles = async (): Promise<Style[]> => {
  const { data, error } = await supabase.from('styles').select('*').order('style_number', { ascending: true });
  if (error || !data) return [];
  return data as Style[];
};

export const fetchStyleByNumber = async (styleNum: string): Promise<Style | null> => {
    const { data, error } = await supabase.from('styles').select('*').eq('style_number', styleNum).maybeSingle();
    if (error || !data) return null;
    return data as Style;
};

export const fetchStyleById = async (id: string): Promise<Style | null> => {
    const { data, error } = await supabase.from('styles').select('*').eq('id', id).single();
    if (error || !data) return null;
    return data as Style;
};

export const upsertStyle = async (style: Partial<Style>): Promise<{ data: Style | null, error: string | null }> => {
  const { data, error } = await supabase.from('styles').upsert([style]).select().single();
  if (error) return { data: null, error: error.message };
  return { data: data as Style, error: null };
};

export const deleteStyle = async (id: string): Promise<void> => {
  await supabase.from('styles').delete().eq('id', id);
};

export const fetchStyleTemplate = async (): Promise<StyleTemplate | null> => {
  const { data, error } = await supabase.from('style_templates').select('*').eq('id', 1).single();
  if (error || !data) return null;
  return data as StyleTemplate;
};

export const updateStyleTemplate = async (config: any[]): Promise<void> => {
  await supabase.from('style_templates').upsert([{ id: 1, config, updated_at: new Date().toISOString() }]);
};

// --- History Management Services ---

export const recordBulkEditHistory = async (description: string, stylesToSnapshot: Style[]): Promise<void> => {
  if (stylesToSnapshot.length === 0) return;

  const snapshot: Record<string, Style> = {};
  stylesToSnapshot.forEach(s => {
    snapshot[s.id] = s;
  });

  const { error } = await supabase.from('bulk_edit_history').insert([{
    description,
    affected_count: stylesToSnapshot.length,
    snapshot
  }]);

  if (error) console.error("History recording failed:", error.message);
};

export const fetchBulkEditHistory = async (): Promise<BulkEditHistory[]> => {
  const { data, error } = await supabase
    .from('bulk_edit_history')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(50);

  if (error || !data) return [];
  return data as BulkEditHistory[];
};

export const undoBulkEdit = async (historyId: string): Promise<{ success: boolean; error?: string }> => {
  const { data: history, error: fetchError } = await supabase
    .from('bulk_edit_history')
    .select('*')
    .eq('id', historyId)
    .single();

  if (fetchError || !history) return { success: false, error: 'History record not found' };

  const snapshot = history.snapshot as Record<string, Style>;
  const styleObjects = Object.values(snapshot);

  try {
    for (const style of styleObjects) {
      await supabase.from('styles').upsert([style]);
    }
    // Delete this history entry once undone to prevent circularity
    await supabase.from('bulk_edit_history').delete().eq('id', historyId);
    return { success: true };
  } catch (err: any) {
    return { success: false, error: err.message };
  }
};

