                        <div style="font-size:12px; font-weight:bold;">${v.text || '---'}</div>
                        <div style="display:grid; grid-template-columns:${vImgs.length === 1 ? '1fr' : '1fr 1fr'}; gap:5px; margin-top:5px;">
