    if (selectedOrderIds.length === 0) return;
    const unitIdStr = prompt(`Enter Unit ID to re-assign ${selectedOrderIds.length} orders to:\n${units.map(u => `${u.id}: ${u.name}`).join('\n')}`);
    if (!unitIdStr) return;
    const unitId = parseInt(unitIdStr);
    if (isNaN(unitId) || !units.find(u => u.id === unitId)) return alert("Invalid Unit ID");

    setBulkProcessing(true);
    try {
      const selectedOrders = orders.filter(o => selectedOrderIds.includes(o.id));
      await recordOrderEditHistory(`Bulk Re-assign: Moved to ${units.find(u => u.id === unitId)?.name}`, selectedOrders);

      const { error } = await supabase.from('orders').update({ unit_id: unitId }).in('id', selectedOrderIds);
      if (error) throw error;

      alert(`Successfully re-assigned ${selectedOrderIds.length} orders.`);
      setSelectedOrderIds([]);
      setIsBulkMode(false);
      loadData();
    } catch (err: any) {
      alert("Bulk update failed: " + err.message);
    } finally {
      setBulkProcessing(false);
    }
  };

  const handleBulkUpdateDate = async () => {
    if (selectedOrderIds.length === 0) return;
    const newDate = prompt("Enter new target delivery date (YYYY-MM-DD):");
    if (!newDate) return;

    setBulkProcessing(true);
    try {
      const selectedOrders = orders.filter(o => selectedOrderIds.includes(o.id));
      await recordOrderEditHistory(`Bulk Date Change: set to ${newDate}`, selectedOrders);

      const { error } = await supabase.from('orders').update({ target_delivery_date: newDate }).in('id', selectedOrderIds);
      if (error) throw error;

      alert("Dates updated successfully.");
      setSelectedOrderIds([]);
      setIsBulkMode(false);
      loadData();
    } catch (err: any) {
      alert("Bulk update failed: " + err.message);
    } finally {
      setBulkProcessing(false);
    }
  };

  const handlePrintUnitReport = async () => {
    setReportLoading(true);
    try {
      const inProgressOrders = orders.filter(o => o.status === OrderStatus.IN_PROGRESS);
      const assignedOrders = orders.filter(o => o.status === OrderStatus.ASSIGNED);
      const allLogs = await fetchOrderLogs();
      const inProgressOrderIds = inProgressOrders.map(o => o.id);
      const recentLogs = allLogs
        .filter(log => inProgressOrderIds.includes(log.order_id))
        .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 5);

      const groupedLogs: Record<string, OrderLog[]> = {};
      recentLogs.forEach(log => {
        if (!groupedLogs[log.order_id]) groupedLogs[log.order_id] = [];
        groupedLogs[log.order_id].push(log);
      });

      const win = window.open('', 'UnitReport', 'width=1000,height=800');
      if (win) {
        const logSectionsHtml = Object.entries(groupedLogs).map(([orderId, logs]) => {
          const order = inProgressOrders.find(o => o.id === orderId);
          const orderRef = order ? formatOrderNumber(order) : 'UNK';
          return `
            <div style="margin-bottom: 20px; border: 1.5px solid #1e293b; border-radius: 8px; overflow: hidden; page-break-inside: avoid;">
              <div style="background: #1e293b; padding: 10px 15px; font-weight: 900; color: #fff; font-size: 13px; text-transform: uppercase;">Job Ref: ${orderRef}</div>
              <table style="width: 100%; border-collapse: collapse; background: #fff;">
                <tbody style="font-size: 11px;">
                  ${logs.map(log => `<tr style="border-bottom: 1px solid #e2e8f0;"><td style="padding: 10px; width: 160px; color: #64748b; font-weight: bold; border-right: 1px solid #e2e8f0;">${new Date(log.created_at).toLocaleString()}</td><td style="padding: 10px; color: #1e293b; font-weight: 500;">${log.message}</td></tr>`).join('')}
                </tbody>
              </table>
            </div>`;
        }).join('');

        const assignedRows = assignedOrders.map(order => `
          <tr>
            <td style="padding: 10px; border: 1px solid #ddd; font-weight: bold;">${formatOrderNumber(order)}</td>
            <td style="padding: 10px; border: 1px solid #ddd;">${order.style_number}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center; font-weight: bold;">${order.quantity}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center;">${order.target_delivery_date}</td>
          </tr>`).join('');

        win.document.write(`
          <html><head><title>Unit Production Report</title><style>body { font-family: sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; background: #fff; } .header { border-bottom: 4px solid #000; padding-bottom: 20px; margin-bottom: 30px; text-align: center; } .brand { font-size: 28px; font-weight: 900; letter-spacing: 1px; } .title { font-size: 16px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-top: 5px; } .section-title { font-size: 14px; font-weight: 900; background: #f1f5f9; padding: 10px 15px; border-left: 6px solid #1e293b; margin: 40px 0 20px 0; text-transform: uppercase; letter-spacing: 1px; } table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; } th { background: #f8fafc; text-align: left; padding: 12px; border: 1px solid #ddd; text-transform: uppercase; font-size: 10px; color: #64748b; } .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #eee; padding-top: 20px; } @media print { body { padding: 20px; } .section-title { -webkit-print-color-adjust: exact; } }</style></head>
          <body>
            <div class="header"><div class="brand">TINTURA SST</div><div class="title">Manufacturing Unit Executive Report</div><div style="font-size: 11px; margin-top: 10px; font-weight: bold; color: #94a3b8;">DISPATCHED: ${new Date().toLocaleString()}</div></div>
            <div class="section-title">Recent Timeline Activity (Last 5 Global Updates)</div>
            ${recentLogs.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">No recent floor activity logs recorded for in-progress jobs.</p>' : logSectionsHtml}
            <div class="section-title">Queue Status (Assigned & Unstarted Jobs)</div>
            ${assignedOrders.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">Assigned queue is currently empty.</p>' : `<table><thead><tr><th width="150">Order Ref</th><th>Style Reference</th><th width="100" style="text-align: center;">Batch Vol</th><th width="120" style="text-align: center;">Target Date</th></tr></thead><tbody>${assignedRows}</tbody></table>`}
            <div class="footer">This report is generated automatically by Tintura SST HQ. <br/>For internal manufacturing supervision only.</div>
            <script>window.onload = () => { setTimeout(() => { window.print(); }, 500); };</script>
          </body></html>`);
        win.document.close();
      }
    } catch (err) { alert("Critical: Failed to compile unit report."); } finally { setReportLoading(false); }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">
          {activeTab === 'overview' ? 'Executive Dashboard' : 'Analytics & Reports'}
        </h2>
        <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('overview')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'overview' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><BarChart3 size={18}/> Overview</button>
                <button onClick={() => setActiveTab('reports')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><PieChart size={18}/> Reports</button>
            </div>
            {activeTab === 'overview' && (
                <div className="flex gap-2">
                  <button 
                    onClick={handleGlobalSync} 
                    disabled={isSyncing}
                    className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-orange-600 rounded-xl transition-all flex items-center gap-2 font-bold text-xs shadow-sm active:scale-95 disabled:opacity-50" 
                    title="Recalculate All Forecasts"
                  >
                    {isSyncing ? <Loader2 size={18} className="animate-spin" /> : <Calculator size={18} className="text-orange-500"/>}
                    <span>Global Sync</span>
                  </button>
                  <button onClick={() => setIsHistoryOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 rounded-xl transition-all" title="Distribution History"><History size={20}/></button>
                  <button onClick={() => { setIsBulkMode(!isBulkMode); setSelectedOrderIds([]); }} className={`p-3 border rounded-xl font-bold text-sm flex items-center gap-2 transition-all ${isBulkMode ? 'bg-orange-600 text-white border-orange-600 shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:text-orange-600'}`}><CheckSquare size={20}/> {isBulkMode ? 'Exit Bulk' : 'Bulk Edit'}</button>
                  <button onClick={handlePrintUnitReport} disabled={reportLoading} className="bg-white border-2 border-indigo-600 text-indigo-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-50 shadow-md transition-all active:scale-95 disabled:opacity-50">{reportLoading ? <Loader2 size={20} className="animate-spin" /> : <ClipboardList size={20} />}<span>Unit Report</span></button>
                  <button onClick={() => setIsLaunchModalOpen(true)} className="bg-indigo-600 text-white px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><PlusCircle size={20} /><span>Launch Order</span></button>
                </div>
            )}
        </div>
      </div>

      {activeTab === 'overview' ? (
        <div className="space-y-6 animate-fade-in">
            <DashboardStats liveStockCount={liveStockCount} activeOrderCount={activeOrderCount} />
            <MasterOrderList 
              orders={orders} 
              units={units} 
              onRefresh={loadData} 
              onViewDetails={setDetailsModal} 
              onSendEmail={handleSendEmail} 
              emailLoading={emailLoading}
              isBulkMode={isBulkMode}
              selectedOrderIds={selectedOrderIds}
              onToggleSelect={(id) => setSelectedOrderIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id])}
            />
        </div>
      ) : (
        <div className="bg-white p-20 rounded-2xl border border-slate-200 text-center text-slate-400 animate-fade-in"><PieChart size={48} className="mx-auto mb-4 opacity-20"/><p className="text-lg font-bold">Reporting Suite</p><p className="text-sm">Detailed production analytics and performance KPIs are currently being compiled.</p></div>
      )}

      {isBulkMode && selectedOrderIds.length > 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-slide-up">
          <div className="bg-slate-900 text-white rounded-full px-8 py-4 shadow-2xl flex items-center gap-6 border border-white/10">
            <div className="flex flex-col"><span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Order Actions</span><span className="text-xl font-black">{selectedOrderIds.length} Selected</span></div>
            <div className="h-10 w-px bg-white/20"></div>
            <div className="flex items-center gap-3">
              <button disabled={bulkProcessing} onClick={handleBulkReassign} className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all flex items-center gap-2 shadow-lg"><Factory size={18}/> Re-assign Facility</button>
              <button disabled={bulkProcessing} onClick={handleBulkUpdateDate} className="bg-orange-600 hover:bg-orange-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all flex items-center gap-2 shadow-lg"><Calendar size={18}/> Update Delivery Date</button>
            </div>
            {bulkProcessing && <Loader2 className="animate-spin text-white" />}
            <button onClick={() => { setSelectedOrderIds([]); setIsBulkMode(false); }} className="text-slate-400 hover:text-white transition-colors ml-2"><X/></button>
          </div>
        </div>
      )}

      <LaunchOrderModal isOpen={isLaunchModalOpen} onClose={() => setIsLaunchModalOpen(false)} units={units} onSuccess={loadData} />
      {detailsModal && <AdminOrderDetailsModal order={detailsModal} units={units} onClose={() => setDetailsModal(null)} onRefresh={loadData} />}
      {isHistoryOpen && <HistoryModal type="order" onClose={() => setIsHistoryOpen(false)} onUndoSuccess={loadData} />}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Pencil, Trash2, Printer, Save, Loader2, Clock, Paperclip, Box, Image as ImageIcon, FileText, Download, ArrowLeftRight, Upload, BookOpen, Calculator, ExternalLink, RefreshCcw } from 'lucide-react';
import { Order, Unit, OrderLog, SizeBreakdown, Attachment, OrderStatus, formatOrderNumber, Style, StyleTemplate, ConsumptionType, DetailedRequirement } from '../../types';
import { fetchOrderLogs, updateOrderDetails, deleteOrder, triggerOrderEmail, uploadOrderAttachment, fetchStyleByNumber, fetchStyleTemplate, fetchStyles, calculateOrderForecast } from '../../services/db';

interface AdminOrderDetailsModalProps {
  order: Order;
  units: Unit[];
  onClose: () => void;
  onRefresh: () => void;
}

export const AdminOrderDetailsModal: React.FC<AdminOrderDetailsModalProps> = ({ order, units, onClose, onRefresh }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editFormData, setEditFormData] = useState<Partial<Order>>({ ...order });
  const [modalLogs, setModalLogs] = useState<OrderLog[]>([]);
  const [useNumericSizes, setUseNumericSizes] = useState(order.size_format === 'numeric');
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [availableStyles, setAvailableStyles] = useState<Style[]>([]);
  const [selectedStyleId, setSelectedStyleId] = useState<string>('');

  useEffect(() => {
    fetchOrderLogs(order.id).then(setModalLogs);
    fetchStyles().then(setAvailableStyles);

    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
        fetchStyleByNumber(styleRefPart).then(s => {
            setLinkedStyle(s);
            if (s) setSelectedStyleId(s.id);
        });
    }
  }, [order.id, order.style_number]);

  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getRowTotal(row), 0);
  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const handleStyleSelect = (styleId: string) => {
    setSelectedStyleId(styleId);
    const style = availableStyles.find(s => s.id === styleId);
    if (!style) return;

    // Autofill Logic: Reference = <style number> - <short description>
    const newStyleNum = `${style.style_number} - ${style.style_text}`;
    setEditFormData(prev => ({
      ...prev,
      style_number: newStyleNum
    }));

    setUseNumericSizes(style.size_type === 'number');
    setLinkedStyle(style);

    // Prompt to update color variants if they exist in the new style
    if (style.available_colors && style.available_colors.length > 0) {
      if (confirm("Would you like to reset the color breakdown based on the new style's colors? (Existing quantities will be lost)")) {
        const newBreakdown = style.available_colors
          .filter(c => c.trim() !== '')
          .map(color => ({
            color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0
          }));
        setEditFormData(prev => ({ ...prev, size_breakdown: newBreakdown }));
      }
    }
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    // If we are currently editing, recalculate dynamically based on form data
    if (isEditing && linkedStyle) {
      return calculateOrderForecast({ ...order, ...editFormData } as Order, linkedStyle);
    }
    // Otherwise, prefer the stored forecast from the database, fall back to calculation
    if (order.material_forecast && order.material_forecast.length > 0) {
      return order.material_forecast;
    }
    if (linkedStyle) {
      return calculateOrderForecast(order, linkedStyle);
    }
    return [];
  };

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const newAttachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) newAttachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }
      const finalAttachments = [...(editFormData.attachments || []), ...newAttachments];
      const finalQty = getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]);

      // Calculate final forecast before saving to ensure DB is in sync
      let finalForecast = order.material_forecast;
      if (linkedStyle) {
        finalForecast = calculateOrderForecast({ ...order, ...editFormData, quantity: finalQty } as Order, linkedStyle);
      }

      const result = await updateOrderDetails(order.id, { 
        ...editFormData, 
        quantity: finalQty, 
        attachments: finalAttachments, 
        size_format: useNumericSizes ? 'numeric' : 'standard',
        material_forecast: finalForecast
      });

      if (result.success) {
        await triggerOrderEmail(order.id, true);
        onRefresh();
        onClose();
      } else {
        alert("Error saving: " + result.error);
      }
    } catch (err: any) {
        alert("Exception: " + err.message);
    } finally {
      setIsUploading(false);
    }
  };

  const handlePrintMaterialForecast = () => {
    const detailedReqs = getDetailedRequirements();
    if (detailedReqs.length === 0) return alert("No projected requirements found.");

    const formattedNo = formatOrderNumber(order);
    const win = window.open('', 'MaterialForecast', 'width=1000,height=800');
    if (win) {
      win.document.write(`
        <html><head><title>Forecast - ${formattedNo}</title>
        <style>
          body { font-family: sans-serif; padding: 30px; font-size: 11px; color: #1e293b; }
          .header { text-align: center; border-bottom: 3px solid #000; padding-bottom: 10px; margin-bottom: 20px; }
          .brand { font-size: 22px; font-weight: 900; }
          .title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-top: 5px; color:#64748b; letter-spacing:1px; }
          .meta { margin-bottom: 20px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; background: #f8fafc; padding: 12px; border: 1px solid #e2e8f0; border-radius: 6px; }
          .section { margin-bottom: 20px; border: 1px solid #cbd5e1; border-radius: 8px; overflow: hidden; page-break-inside: avoid; }
          .section-header { background: #334155; color: #fff; padding: 8px 12px; font-weight: bold; font-size: 12px; display: flex; justify-content: space-between; align-items: center; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #cbd5e1; padding: 6px; text-align: left; vertical-align: top; }
          th { background: #f1f5f9; text-transform: uppercase; font-size: 9px; color: #64748b; }
          .qty-val { font-weight: 900; color: #4f46e5; font-size: 13px; }
          .img-grid { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 5px; }
          .img-grid img { height: 60px; border-radius: 3px; border: 1px solid #ddd; }
          .footer { margin-top: 30px; text-align: center; font-size: 9px; color: #94a3b8; border-top: 1px solid #e2e8f0; padding-top: 15px; }
        </style>
        </head><body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Projected Material Requirements Forecast</div>
          </div>
          <div class="meta">
            <div><strong>Order:</strong> ${formattedNo}</div>
            <div><strong>Style:</strong> ${isEditing ? editFormData.style_number : order.style_number}</div>
            <div><strong>Batch:</strong> ${isEditing ? getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]) : order.quantity} PCS</div>
            <div><strong>Date:</strong> ${new Date().toLocaleDateString()}</div>
          </div>
          ${detailedReqs.map(req => `
            <div class="section">
              <div class="section-header"><span>${req.name}</span><span style="background:rgba(255,255,255,0.2); padding:2px 8px; border-radius:4px;">TOTAL JOB REQ: ${req.total}</span></div>
              <table>
                <thead><tr><th>Segment Scope</th><th style="text-align:center">Base Qty</th><th style="text-align:right">Calculated Req.</th><th>Instructions & Visuals</th></tr></thead>
                <tbody>${req.breakdown.map(b => `
                  <tr>
                    <td><strong>${b.label}</strong></td>
                    <td style="text-align:center">${b.count}</td>
                    <td style="text-align:right" class="qty-val">${b.calc}</td>
                    <td>
                        <div style="font-weight:bold; margin-bottom:4px;">${b.text || '---'}</div>
                        <div class="img-grid">${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}"/>`).join('')}</div>
                    </td>
                  </tr>`).join('')}
                </tbody>
              </table>
            </div>
          `).join('')}
          <div class="footer">Document generated via Tintura SST MES. Estimates are for internal production planning only.</div>
          <script>window.onload = () => { window.print(); };</script>
        </body></html>
      `);
      win.document.close();
    }
  };

  const handlePrint = async () => {
    let techPackHtml = '';
    let preProductionHtml = '';

    const activeStyleNumber = isEditing ? editFormData.style_number : order.style_number;
    const styleRefPart = activeStyleNumber!.split(' - ')[0].trim();
    if (styleRefPart) {
        const [style, template] = await Promise.all([ fetchStyleByNumber(styleRefPart), fetchStyleTemplate() ]);
        if (style && template) {
            const renderField = (f: string, catName: string) => {
                const item = style.tech_pack[catName]?.[f] || { text: 'N/A', attachments: [] };
                let contentHtml = '';
                if (item.variants) {
                  contentHtml = item.variants.map(v => {
                    let sizeHtml = '';
                    const vImgs = v.attachments.filter(a => a.type === 'image');
                    if (v.sizeVariants) {
                      sizeHtml = `<div style="margin-top:8px; display:grid; grid-template-columns:1fr; gap:6px;">${v.sizeVariants.map(sv => {
                        const svImgs = sv.attachments.filter(a => a.type === 'image');
                        return `
                        <div style="background:#fff; border:1px solid #ddd; border-left:3px solid #4f46e5; padding:8px; border-radius:4px; page-break-inside:avoid;">
                          <div style="font-size:9px; font-weight:bold; color:#4f46e5; margin-bottom:2px;">SIZES: ${sv.sizes.join(', ')}</div>
                          <div style="font-size:11px; font-weight:bold;">${sv.text || '---'}</div>
                          <div style="display:grid; grid-template-columns:${svImgs.length === 1 ? '1fr' : '1fr 1fr'}; gap:5px; margin-top:5px;">
                            ${svImgs.map(a => `<img src="${a.url}" style="width:100%; border-radius:2px; border:1px solid #ddd;"/>`).join('')}
                          </div>
                        </div>
                      `}).join('')}</div>`;
                    }
                    return `
                      <div style="border:1px solid #e2e8f0; padding:10px; border-radius:6px; margin-top:8px; background:#f8fafc; page-break-inside:avoid;">
                        <div style="margin-bottom:4px;">${v.colors.map(c => `<span style="background:#334155; color:#fff; font-size:8px; font-weight:bold; padding:1px 5px; border-radius:2px; margin-right:3px; text-transform:uppercase;">${c}</span>`).join('')}</div>
                        <div style="font-size:12px; font-weight:bold;">${v.text || '---'}</div>
                        <div style="display:grid; grid-template-columns:${vImgs.length === 1 ? '1fr' : '1fr 1fr'}; gap:5px; margin-top:5px;">
                          ${vImgs.map(a => `<img src="${a.url}" style="width:100%; border-radius:3px; border:1px solid #ddd;"/>`).join('')}
                        </div>
                        ${sizeHtml}
                      </div>`;
                  }).join('');
                } else {
                  const itemImgs = item.attachments.filter(a => a.type === 'image');
                  contentHtml = `
                    <div style="font-size:12px; background:#f8fafc; padding:10px; border-radius:6px; border:1px solid #e2e8f0; font-weight:bold;">
                      ${item.text || '---'}
                      <div style="display:grid; grid-template-columns:${itemImgs.length === 1 ? '1fr' : '1fr 1fr'}; gap:8px; margin-top:8px;">
                        ${itemImgs.map(a => `<img src="${a.url}" style="width:100%; border-radius:4px; border:1px solid #ddd;"/>`).join('')}
                      </div>
                    </div>`;
                }
                return `<div style="margin-bottom:12px; page-break-inside:avoid;"><div style="font-size:9px; font-weight:bold; color:#94a3b8; text-transform:uppercase; margin-bottom:5px;">${f}</div>${contentHtml}</div>`;
            };

            const preProdCat = template.config.find(c => c.name.toLowerCase().includes('pre production'));
            if (preProdCat) {
                preProductionHtml = `
                    <div style="page-break-before:always; margin-top:30px;">
                        <h3 style="background:#334155; color:#fff; padding:6px 12px; font-size:11px; text-transform:uppercase; border-radius:4px;">Pre-Production Requirements</h3>
                        <div style="padding:10px 0;">${preProdCat.fields.map(f => renderField(f, preProdCat.name)).join('')}</div>
                    </div>`;
            }

            techPackHtml = template.config.filter(c => 
              c.name !== "General Info" && 
              !c.name.toLowerCase().includes('pre production') && 
              !c.name.toLowerCase().includes('packing') &&
              !c.name.toLowerCase().includes('requirements during production')
            ).map(cat => {
