                      ))}
                      <td className="p-3 font-black text-indigo-700 bg-slate-50/50 tabular-nums text-lg">{getBreakdownRowTotal(row, currentSizes)}</td>
                      <td className="p-3">{breakdown.length > 1 && <button type="button" onClick={() => setBreakdown(breakdown.filter((_, i) => i !== idx))} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20}/></button>}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <button type="button" onClick={() => setBreakdown([...breakdown, { color: '' }])} className="w-full py-5 text-[10px] font-black text-indigo-600 hover:bg-indigo-50 border-t border-slate-100 transition-colors bg-slate-50/20 uppercase tracking-widest flex items-center justify-center gap-2"><PlusCircle size={16}/> Add New Color Variant</button>
