                            value={row[label] || ''} 
                            onChange={e => onUpdateRow(idx, label, parseInt(e.target.value) || 0)} 
                          />
                        </td>
                      ))}
                      <td className="p-3 font-bold bg-slate-50">{getBreakdownRowTotal(row, sizeLabels)}</td>
                    </tr>
                  ))}
