              </table>
            </div>
          </div>

          <div className="flex justify-end gap-3 pt-4 border-t">
            <button type="button" onClick={onClose} className="px-6 py-2 font-bold text-slate-500">Back</button>
            <button type="submit" className="bg-green-600 text-white px-10 py-3 rounded-xl font-extrabold shadow-lg hover:bg-green-700 flex items-center gap-2 transition-all active:scale-95">
              <CheckCircle2 /> Submit Production & Finish Job
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

