          .header { text-align: center; border-bottom: 3.5px solid #000; padding-bottom: 12px; margin-bottom: 18px; }
          .brand { font-size: 28px; font-weight: 900; }
          .grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-bottom: 15px; }
          .box { padding: 8px 12px; border: 1.5px solid #1e293b; border-radius:6px; }
          .label { font-size: 7px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-bottom:2px; display:block; }
          .value { font-size: 13px; font-weight: bold; }
          table { width: 100%; border-collapse: collapse; margin-top: 10px; }
          th, td { border: 1px solid #1e293b; padding: 6px; text-align: center; }
          th { background: #f8fafc; font-weight: bold; font-size: 8px; text-transform:uppercase; }
          .section-title { font-size: 12px; font-weight: 900; border-bottom: 1.5px solid #1e293b; margin-top: 20px; margin-bottom: 8px; text-transform: uppercase; padding-bottom:2px; }
          .notes-box { padding: 10px 15px; border: 1.5px solid #1e293b; background: #f8fafc; border-radius: 6px; font-size: 11px; font-weight:bold; white-space: pre-wrap; }
        </style>
        </head><body>
          <div class="header"><div class="brand">TINTURA SST</div><div>Manufacturing Job Execution</div></div>
          <div class="grid">
            <div class="box"><span class="label">Job ID</span><div class="value">${formattedNo}</div></div>
            <div class="box"><span class="label">Style</span><div class="value">${activeStyleNumber}</div></div>
            <div class="box"><span class="label">Batch Qty</span><div class="value">${isEditing ? (editFormData.quantity || 0) : order.quantity} PCS</div></div>
            <div class="box"><span class="label">Target Date</span><div class="value">${isEditing ? editFormData.target_delivery_date : order.target_delivery_date}</div></div>
          </div>
          <div class="section-title">Color & Size Matrix</div>
          <table><thead><tr><th style="text-align:left; border:1px solid #333;">Variant</th>${headers.map(h => `<th style="border:1px solid #333;">${h}</th>`).join('')}<th style="border:1px solid #333;">Total</th></tr></thead><tbody>${breakdownRows}</tbody></table>
          <div class="section-title">Manufacturing Notes</div>
          <div class="notes-box">${isEditing ? editFormData.description : order.description || 'N/A'}</div>
          <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
        </body></html>`);
        win.document.close();
    }
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-start bg-white">
          <div>
            <h3 className="text-3xl font-black text-slate-800 tracking-tight">{formatOrderNumber(order)}</h3>
            {isEditing && <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest mt-1">Editing Mode Active</p>}
          </div>
          <div className="flex items-center gap-3">
            {!isEditing && <button onClick={() => setIsEditing(true)} className="bg-indigo-50 text-indigo-700 border border-indigo-100 px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-600 hover:text-white transition-all"><Pencil size={18} /> Modify Order</button>}
            <button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full"><X size={32}/></button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">
          {isEditing && (
            <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100 animate-fade-in space-y-6">
              <div className="flex flex-col md:flex-row items-center gap-6">
                <div className="flex items-center gap-3 shrink-0">
                  <div className="p-3 bg-white rounded-xl text-indigo-600 shadow-sm border border-indigo-50"><BookOpen size={24}/></div>
                  <div>
                    <h4 className="font-black text-indigo-900 text-sm uppercase">Change Technical Style</h4>
                    <p className="text-indigo-400 text-[10px] font-bold uppercase tracking-widest mt-1">Relink to a different blueprint</p>
                  </div>
                </div>
                <div className="flex-1 w-full">
                  <select 
                    className="w-full bg-white border-2 border-indigo-200 rounded-xl px-5 py-4 text-sm font-black text-indigo-700 outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-sm"
                    value={selectedStyleId}
                    onChange={e => handleStyleSelect(e.target.value)}
                  >
                    <option value="">-- No linked style --</option>
                    {availableStyles.map(s => <option key={s.id} value={s.id}>{s.style_number} - {s.style_text}</option>)}
                  </select>
                </div>
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
                <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Reference Text</span>
                {isEditing ? <input className="w-full border rounded p-2 text-sm font-bold" value={editFormData.style_number} onChange={e => setEditFormData({...editFormData, style_number: e.target.value})}/> : <div className="text-sm font-black">{order.style_number}</div>}
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Volume</span>
              <div className="text-2xl font-black text-slate-800">{isEditing ? getTotalQuantity(editFormData.size_breakdown || []) : order.quantity} PCS</div>
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Delivery</span>
              {isEditing ? <input type="date" className="w-full border rounded p-2 font-bold" value={editFormData.target_delivery_date} onChange={e => setEditFormData({...editFormData, target_delivery_date: e.target.value})}/> : <div className="text-lg font-black">{order.target_delivery_date}</div>}
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Facility Unit</span>
              {isEditing ? <select className="w-full border rounded p-2 bg-white font-bold" value={editFormData.unit_id} onChange={e => setEditFormData({...editFormData, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select> : <div className="text-lg font-black">{units.find(u => u.id === order.unit_id)?.name}</div>}
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>
              {isEditing && <button type="button" onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '' }]})} className="text-[10px] bg-indigo-600 text-white px-4 py-2 rounded-xl font-black uppercase">+ Add Color</button>}
            </div>
            <div className="border border-slate-200 rounded-3xl overflow-x-auto shadow-sm bg-white">
              <table className="w-full text-center text-sm border-collapse min-w-full">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] border-b">
                  <tr>
                    <th className="p-4 text-left border-r sticky left-0 bg-slate-50 z-10">Color Variant</th>
                    {sizeLabels.map(h => <th key={h} className="p-4 border-r min-w-[80px]">{h}</th>)}
                    <th className="p-4 bg-slate-100 min-w-[100px]">Sum</th>
                    {isEditing && <th className="p-4 w-12"></th>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50">
                      <td className="p-4 text-left font-black text-slate-700 border-r sticky left-0 bg-white z-10">
                        {isEditing ? <input className="w-full border rounded p-1 font-bold text-sm" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}
                      </td>
                      {sizeLabels.map(label => (
                        <td key={label} className="p-4 border-r">
                          {isEditing ? <input type="number" className="w-full border rounded p-1 text-center font-black" value={row[label] || ''} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx][label] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : (row[label] || 0)}
                        </td>
                      ))}
                      <td className="p-4 font-black text-slate-900 bg-slate-50/50">{getBreakdownRowTotal(row, sizeLabels)}</td>
                      {isEditing && <td className="p-4"><button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600"><Trash2 size={20}/></button></td>}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col">
            <h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6"><Clock size={16}/> Lifecycle status log</h4>
            <div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">
              {modalLogs.map(log => (
                <div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2">
                  <div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">
                    {new Date(log.created_at).toLocaleDateString()}<br/>
                    <span className="text-indigo-400 opacity-60">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                  </div>
                  <div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-200"><p className="text-slate-700 font-bold leading-snug">{log.message}</p></div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 border-t bg-slate-50 flex justify-between items-center shadow-inner">
          <div className="flex gap-2">
            {!isEditing && <button onClick={() => { if(confirm("Permanently delete this order?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all"><Trash2 size={24}/></button>}
            {isEditing && <button onClick={() => { setIsEditing(false); setEditFormData({...order}); setLinkedStyle(null); }} className="px-6 py-3 bg-white text-slate-400 border border-slate-200 rounded-xl font-black uppercase text-xs hover:bg-slate-100 transition-all">Cancel</button>}
          </div>
          <div className="flex items-center gap-4">
            <button onClick={handlePrint} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2 shadow-sm hover:bg-indigo-50"><Printer size={16}/> Print Job Sheet</button>
            {!isEditing && <button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs hover:bg-slate-700">Close</button>}
            {isEditing && <button onClick={handleSave} disabled={isUploading} className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs shadow-lg hover:bg-indigo-700 flex items-center gap-2">{isUploading ? <Loader2 className="animate-spin" size={16}/> : <Save size={18}/>} Save Changes</button>}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType, Attachment } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    const hasInProgress = selectedOrders.some(id => {
      const o = orders.find(ord => ord.id === id);
      return o?.status === OrderStatus.IN_PROGRESS;
    });

    if (hasInProgress) {
      if (!confirm("Warning: Some selected orders are being sent to QC Approval. Once sent, this action cannot be withdrawn. Proceed with bulk update?")) {
        return;
      }
    }

    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.IN_PROGRESS) {
      if (!confirm("Warning: This order will be sent to QC Approval. Once sent to the QC Department, this action cannot be withdrawn from the sub-unit panel. Proceed?")) {
        return;
      }
    }

    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color }))
                : [{ color: 'Standard' }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><Box size={28}/></div> Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100">Unit ID: {CURRENT_UNIT_ID}</div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm w-full bg-white text-slate-900" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center text-slate-400">No production orders found in this section.</div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                return (
                    <tr key={order.id} className="hover:bg-slate-50/80 transition-colors group cursor-pointer" onClick={() => setDetailsModal(order)}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800">{formatOrderNumber(order)}</div>
                        <div className="text-xs font-bold text-slate-400 mt-1">Due: {order.target_delivery_date}</div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase">Target: {order.quantity} pcs</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => setDetailsModal(order)} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200"><Eye size={20}/></button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formatOrderNumber(order))} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200"><Printer size={20}/></button>
                                <button onClick={() => setMaterialModal(order.id)} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase text-white ${isReadyToComplete ? 'bg-green-600' : 'bg-indigo-600'}`}>
                                        {isReadyToComplete ? <CheckCircle2 size={18} /> : <ArrowRight size={18} />}
                                        <span>{isReadyToComplete ? 'Finalize' : 'Advance'}</span>
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => {}} 
          onPrintMaterials={() => {}}
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={() => {}} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={formatOrderNumber(orders.find(o => o.id === materialModal)!)} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={null} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, SizeBreakdown, Style, Attachment, getBreakdownRowTotal, getOrderSizeLabels, DetailedRequirement } from '../../types';
import { X, ImageIcon, FileText, Download, Paperclip, Printer, Box, Calculator } from 'lucide-react';
import { fetchStyleByNumber, calculateOrderForecast } from '../../services/db';

interface OrderDetailsModalProps {
  order: Order;
  useNumericSizes: boolean;
  onToggleSizeFormat: () => void;
  onClose: () => void;
  onPrint: () => void;
  onPrintMaterials: () => void;
}

export const OrderDetailsModal: React.FC<OrderDetailsModalProps> = ({
  order,
  onClose,
  onPrint,
  onPrintMaterials
}) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
      fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.style_number]);

  const sizeLabels = getOrderSizeLabels(order);

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (order.material_forecast && order.material_forecast.length > 0) {
      return order.material_forecast;
    }
    if (linkedStyle) {
      return calculateOrderForecast(order, linkedStyle);
    }
    return [];
  };

  const renderDetailCell = (rowIdx: number, sizeLabel: string) => {
    const plannedRow = order.size_breakdown?.[rowIdx];
    const actualRow = order.completion_breakdown?.[rowIdx];
    const plannedVal = plannedRow ? (Number(plannedRow[sizeLabel]) || 0) : 0;

    if (order.status !== OrderStatus.COMPLETED || !actualRow) {
      return <span className="text-slate-600 font-medium">{plannedVal}</span>;
    }

    const actualVal = Number(actualRow[sizeLabel]) || 0;
    const isMismatch = actualVal !== plannedVal;

    return (
      <div className="flex flex-col items-center justify-center p-1 bg-slate-50 rounded border border-slate-100 min-w-[60px]">
        <span className={`text-lg font-black ${isMismatch ? 'text-indigo-700' : 'text-slate-900'}`}>
          {actualVal}
        </span>
        <span className="text-[10px] font-bold text-slate-400 border-t border-slate-200 w-full text-center mt-0.5 pt-0.5">
          Plan: {plannedVal}
        </span>
      </div>
    );
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden max-h-[95vh] flex flex-col animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{order.order_no}</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Production Execution Details</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={28} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Style Number</span>
              <span className="text-lg font-black text-slate-800">{order.style_number}</span>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Delivery Date</span>
              <span className="text-lg font-black text-slate-800">{order.target_delivery_date}</span>
            </div>
            <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
              <span className="block text-indigo-400 text-[10px] uppercase font-black mb-1 flex items-center gap-1"><Box size={12}/> Planned Boxes</span>
              <span className="text-xl font-black text-indigo-800">{order.box_count || '---'}</span>
            </div>
            {order.status === OrderStatus.COMPLETED && (
               <div className="p-4 bg-green-50 rounded-xl border border-green-100 shadow-sm">
                <span className="block text-green-500 text-[10px] uppercase font-black mb-1 flex items-center gap-1"><Box size={12}/> Actual Packed</span>
                <span className="text-xl font-black text-green-800">{order.actual_box_count}</span>
              </div>
            )}
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Production Matrix</h4>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-x-auto shadow-md">
              <table className="w-full text-center text-sm border-collapse min-w-full">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] border-b">
                  <tr>
