interface MaterialRequestModalProps {
  orderId: string;
  orderNo: string;
  orders: Order[];
  onClose: () => void;
  isEditingRequest: { id: string; originalData: MaterialRequest } | null;
  useNumericSizes: boolean;
  onRefresh: () => void;
}

export const MaterialRequestModal: React.FC<MaterialRequestModalProps> = ({
  orderId,
  orderNo,
  orders,
  onClose,
  isEditingRequest,
  onRefresh
}) => {
  const [loading, setLoading] = useState(false);
  const [forecastItems, setForecastItems] = useState<DetailedRequirement[]>([]);
  const [requestForm, setRequestForm] = useState({
    material_content: '',
    quantity_requested: 0,
    unit: 'Nos'
  });

  const order = orders.find(o => o.id === orderId);

  useEffect(() => {
    if (order) {
      if (order.material_forecast && order.material_forecast.length > 0) {
        setForecastItems(order.material_forecast);
      } else {
        const styleRef = order.style_number.split(' - ')[0].trim();
        fetchStyleByNumber(styleRef).then(style => {
          if (style) setForecastItems(calculateOrderForecast(order, style));
        });
      }
    }
    if (isEditingRequest) {
      setRequestForm({
        material_content: isEditingRequest.originalData.material_content,
        quantity_requested: isEditingRequest.originalData.quantity_requested,
        unit: isEditingRequest.originalData.unit || 'Nos'
      });
    }
  }, [order, isEditingRequest]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (isEditingRequest) {
        await updateMaterialRequest(isEditingRequest.id, requestForm);
      } else {
        await createMaterialRequest({ ...requestForm, order_id: orderId });
      }
      onRefresh();
      onClose();
    } finally {
      setLoading(false);
    }
  };

  const handleSelectForecast = (item: DetailedRequirement) => {
    setRequestForm({
      material_content: item.name,
      quantity_requested: item.total,
      unit: item.name.toLowerCase().includes('thread') ? 'Cones' : 'Nos'
    });
  };

  return (
    <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col animate-scale-up">
        <div className="p-6 border-b bg-blue-50 flex justify-between items-center">
          <h3 className="text-xl font-bold text-blue-900 flex items-center gap-2">
            <PackagePlus /> {isEditingRequest ? 'Edit Material Request' : 'New Material Requisition'}
          </h3>
          <button onClick={onClose} className="text-blue-400 hover:text-blue-600"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
              <Calculator size={14}/> Blueprint Forecast Suggestions
            </div>
            <div className="space-y-3">
              {forecastItems.map((item, idx) => (
                <button 
                  key={idx}
                  onClick={() => handleSelectForecast(item)}
                  className="w-full text-left p-4 bg-slate-50 border border-slate-200 rounded-xl hover:border-blue-400 hover:bg-blue-50 transition-all group"
                >
                  <div className="flex justify-between items-center">
                    <span className="font-bold text-slate-700">{item.name}</span>
                    <span className="text-lg font-black text-blue-600">{item.total}</span>
                  </div>
                  <p className="text-[10px] text-slate-400 uppercase mt-1">Suggested based on Style DB</p>
                </button>
              ))}
              {forecastItems.length === 0 && <p className="text-center text-slate-300 py-10 border-2 border-dashed rounded-xl uppercase text-xs font-bold">No suggestions available</p>}
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
              <FilePlus size={14}/> Requisition Form
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Item Description</label>
              <input 
                required className="w-full border rounded-xl p-3 bg-white text-slate-900 font-bold"
                value={requestForm.material_content}
                onChange={e => setRequestForm({...requestForm, material_content: e.target.value})}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Qty Required</label>
                <input 
                  type="number" step="any" required className="w-full border rounded-xl p-3 bg-white text-slate-900 font-black"
                  value={requestForm.quantity_requested || ''}
                  onChange={e => setRequestForm({...requestForm, quantity_requested: parseFloat(e.target.value) || 0})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Unit</label>
                <select 
                  className="w-full border rounded-xl p-3 bg-white text-slate-900 font-bold"
                  value={requestForm.unit}
                  onChange={e => setRequestForm({...requestForm, unit: e.target.value})}
                >
                  <option value="Nos">Nos</option>
                  <option value="Cones">Cones</option>
                  <option value="Kgs">Kgs</option>
                  <option value="Meters">Meters</option>
                </select>
              </div>
            </div>

            <div className="p-4 bg-orange-50 border border-orange-100 rounded-xl text-xs text-orange-700 leading-relaxed italic">
              * This request will be sent to the Materials Department for verification and partial/full approval.
            </div>

            <div className="flex justify-end gap-3 pt-6 border-t">
              <button type="button" onClick={onClose} className="px-6 py-2 font-bold text-slate-500">Discard</button>
              <button disabled={loading} type="submit" className="bg-blue-600 text-white px-10 py-3 rounded-xl font-black shadow-lg hover:bg-blue-700 flex items-center gap-2">
                {loading ? <Loader2 className="animate-spin" /> : <Send size={18}/>}
                {isEditingRequest ? 'Save Update' : 'Submit Requisition'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

