export const getNextOrderStatus = (current: OrderStatus): OrderStatus | null => {
  switch (current) {
    case OrderStatus.ASSIGNED: return OrderStatus.IN_PROGRESS;
    case OrderStatus.IN_PROGRESS: return OrderStatus.QC;
    case OrderStatus.QC: return OrderStatus.QC_APPROVED;
    case OrderStatus.QC_APPROVED: return OrderStatus.COMPLETED; 
    case OrderStatus.PACKED: return OrderStatus.COMPLETED;
    default: return null;
  }
};

export const getNextBarcodeStatus = (current: BarcodeStatus): BarcodeStatus | null => {
  switch (current) {
    case BarcodeStatus.GENERATED: return BarcodeStatus.DETAILS_FILLED;
    case BarcodeStatus.DETAILS_FILLED: return BarcodeStatus.PUSHED_OUT_OF_SUBUNIT;
    case BarcodeStatus.PUSHED_OUT_OF_SUBUNIT: return BarcodeStatus.QC_APPROVED;
    case BarcodeStatus.QC_APPROVED: return BarcodeStatus.COMMITTED_TO_STOCK;
    case BarcodeStatus.COMMITTED_TO_STOCK: return BarcodeStatus.SOLD;
    default: return null;
  }
};

export const formatOrderNumber = (order: Partial<Order>): string => {
  if (!order.order_no) return 'ORD-NEW';
  const numericMatch = order.order_no.match(/ORD-(\d+)/);
  const serial = numericMatch ? numericMatch[1] : order.order_no;
  const stylePart = order.style_number 
    ? order.style_number.split('-')[0].trim() 
    : 'STYLE';
  return `ORD-${stylePart}-${serial}`;
};

// --- Size Normalization Mapping ---
export const getSizeVariants = (label: string): string[] => {
  const clean = label.trim().toUpperCase();
  if (clean === '2XL' || clean === 'XXL') return ['2XL', 'XXL'];
  if (clean === '3XL' || clean === 'XXXL') return ['3XL', 'XXXL'];
  if (clean === '4XL' || clean === 'XXXXL') return ['4XL', 'XXXXL'];
  if (clean === '5XL' || clean === 'XXXXXL') return ['5XL', 'XXXXXL'];
  return [clean];
};

/**
 * Retrieves quantity from a breakdown row for a specific size label,
 * checking for common equivalents (e.g., if checking for XXL, it also checks 2XL).
 */
export const getQuantityForSize = (row: SizeBreakdown, targetLabel: string): number => {
  const variants = getSizeVariants(targetLabel);
  // Try finding a direct match or a variant match in row keys
  for (const variant of variants) {
    if (row[variant] !== undefined) return Number(row[variant]) || 0;
  }
  // Try case-insensitive fallback for non-normalized keys in data
  const keys = Object.keys(row);
  for (const k of keys) {
    if (variants.includes(k.toUpperCase())) return Number(row[k]) || 0;
  }
  return 0;
};

// Global Helper to calculate row totals for SizeBreakdown
export const getBreakdownRowTotal = (row: SizeBreakdown, labels?: string[]): number => {
  if (!labels) {
    // Fallback: Sum all numeric fields except color
    return Object.entries(row).reduce((acc, [key, val]) => {
      if (key === 'color') return acc;
      return acc + (Number(val) || 0);
    }, 0);
  }
  // Use our specialized quantity getter to ensure variants like 2XL/XXL are summed correctly if mixed (though they shouldn't be in same row)
  return labels.reduce((acc, label) => acc + getQuantityForSize(row, label), 0);
};

export const getOrderSizeLabels = (order: Partial<Order>): string[] => {
  if (!order.size_breakdown || order.size_breakdown.length === 0) return [];
  // Use the first row to determine available labels
  const keys = Object.keys(order.size_breakdown[0]).filter(k => k !== 'color');
  return keys;
};

