import React, { useState, useEffect } from 'react';
import { X, Plus, PlusCircle, Trash2, Upload, ImageIcon, Send, Loader2, BookOpen, Ruler, ChevronLeft, ChevronRight, GripHorizontal } from 'lucide-react';
import { Unit, SizeBreakdown, Attachment, Style, getBreakdownRowTotal } from '../../types';
import { createOrder, uploadOrderAttachment, triggerOrderEmail, fetchStyles } from '../../services/db';

interface LaunchOrderModalProps {
  isOpen: boolean;
  onClose: () => void;
  units: Unit[];
  onSuccess: () => void;
}

export const LaunchOrderModal: React.FC<LaunchOrderModalProps> = ({ isOpen, onClose, units, onSuccess }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [availableStyles, setAvailableStyles] = useState<Style[]>([]);
  const [selectedStyleId, setSelectedStyleId] = useState<string>('');
  const [newOrder, setNewOrder] = useState({ style_number: '', unit_id: 1, target_delivery_date: '', description: '', box_count: 0 });

  // Dynamic Size Management (Ordered list of labels)
  const [currentSizes, setCurrentSizes] = useState<string[]>(['S', 'M', 'L', 'XL', 'XXL', '3XL']);
  const [newSizeInput, setNewSizeInput] = useState('');
  const [breakdown, setBreakdown] = useState<SizeBreakdown[]>([{ color: '' }]);

  useEffect(() => {
    if (isOpen) {
      fetchStyles().then(setAvailableStyles);
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleStyleSelect = (styleId: string) => {
    setSelectedStyleId(styleId);
    const style = availableStyles.find(s => s.id === styleId);
    if (!style) {
      setNewOrder({ ...newOrder, style_number: '' });
      return;
    }

    setNewOrder({
      ...newOrder,
      style_number: `${style.style_number} - ${style.style_text}`
    });

    if (style.available_sizes && style.available_sizes.length > 0) {
      setCurrentSizes([...style.available_sizes]);
    } else {
      setCurrentSizes(style.size_type === 'number' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']);
    }

    if (style.available_colors && style.available_colors.length > 0) {
      const newBreakdown = style.available_colors
        .filter(c => c.trim() !== '')
        .map(color => ({ color }));
      if (newBreakdown.length > 0) setBreakdown(newBreakdown);
    }
  };

  const handleAddSize = () => {
    const val = newSizeInput.trim();
    if (!val) return;
    if (currentSizes.some(s => s.toUpperCase() === val.toUpperCase())) {
      alert("Size already exists in pool.");
      return;
    }
    setCurrentSizes(prev => [...prev, val]);
    setNewSizeInput('');
  };

  const handleRemoveSize = (label: string) => {
    if (currentSizes.length <= 1) return;
    setCurrentSizes(prev => prev.filter(s => s !== label));
    setBreakdown(prev => prev.map(row => {
      const newRow = { ...row };
      delete newRow[label];
      return newRow;
    }));
  };

  const moveSize = (index: number, direction: 'left' | 'right') => {
    const newSizes = [...currentSizes];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newSizes.length) return;
    [newSizes[index], newSizes[targetIndex]] = [newSizes[targetIndex], newSizes[index]];
    setCurrentSizes(newSizes);
  };

  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getBreakdownRowTotal(row, currentSizes), 0);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const quantity = getTotalQuantity(breakdown);
    if (quantity === 0) return alert("Total quantity cannot be zero");

    setIsUploading(true);
    try {
      const attachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) attachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }

      const hasLetters = currentSizes.some(s => /[a-zA-Z]/.test(s));

      const { data, error } = await createOrder({ 
        ...newOrder, 
        quantity, 
        size_breakdown: breakdown, 
        attachments, 
        size_format: hasLetters ? 'standard' : 'numeric' 
      });
      if (data) {
        await triggerOrderEmail(data.id, false);
        onSuccess();
        onClose();
      } else {
        alert(`Error: ${error}`);
      }
    } catch (err: any) {
      alert(`Failed: ${err.message}`);
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <h3 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-lg shadow-lg"><Plus size={24}/></div>
            Launch Production Order
          </h3>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={32}/></button>
        </div>
        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8">

          <div className="bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100 flex flex-col md:flex-row items-center gap-6">
            <div className="flex items-center gap-3 shrink-0">
               <div className="p-3 bg-white rounded-xl text-indigo-600 shadow-sm border border-indigo-50">
                 <BookOpen size={24}/>
               </div>
               <div>
                 <h4 className="font-black text-indigo-900 text-sm uppercase tracking-tight leading-none">Style Template</h4>
                 <p className="text-indigo-400 text-[10px] font-bold uppercase tracking-widest mt-1">Pre-fill details from tech database</p>
               </div>
            </div>
            <div className="flex-1 w-full">
              <select 
                className="w-full bg-white border-2 border-indigo-200 rounded-xl px-5 py-4 text-sm font-black text-indigo-700 outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-sm"
                value={selectedStyleId}
                onChange={e => handleStyleSelect(e.target.value)}
              >
                <option value="">-- Manual Launch (Optional: select style for auto-fill) --</option>
                {availableStyles.map(s => (
                  <option key={s.id} value={s.id}>{s.style_number} - {s.style_text}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Style Reference</label><input required className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.style_number} onChange={e => setNewOrder({...newOrder, style_number: e.target.value})}/></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Assign Facility</label><select className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.unit_id} onChange={e => setNewOrder({...newOrder, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Planned Box Count</label><input required type="number" min="1" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.box_count} onChange={e => setNewOrder({...newOrder, box_count: parseInt(e.target.value) || 0})}/></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Delivery Due</label><input required type="date" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.target_delivery_date} onChange={e => setNewOrder({...newOrder, target_delivery_date: e.target.value})}/></div>
          </div>

          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <Ruler size={18} className="text-indigo-600"/>
                <h4 className="text-xs font-black text-slate-700 uppercase tracking-widest">Manage Matrix Sizes & Sequence</h4>
              </div>
              <div className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1"><GripHorizontal size={12}/> Use arrows to arrange columns</div>
            </div>
            <div className="flex flex-wrap gap-2.5 mb-5">
              {currentSizes.map((label, idx) => (
                <div key={`${label}-${idx}`} className="bg-white border border-indigo-100 rounded-xl px-3 py-2 flex items-center gap-3 shadow-sm group hover:border-indigo-400 transition-all">
                  <div className="flex items-center gap-1 border-r border-slate-100 pr-2">
                    <button type="button" disabled={idx === 0} onClick={() => moveSize(idx, 'left')} className="p-0.5 text-slate-300 hover:text-indigo-600 disabled:opacity-0 transition-colors"><ChevronLeft size={16}/></button>
                    <button type="button" disabled={idx === currentSizes.length - 1} onClick={() => moveSize(idx, 'right')} className="p-0.5 text-slate-300 hover:text-indigo-600 disabled:opacity-0 transition-colors"><ChevronRight size={16}/></button>
                  </div>
                  <span className="font-black text-indigo-700 text-xs min-w-[20px] text-center">{label}</span>
                  <button type="button" onClick={() => handleRemoveSize(label)} className="text-slate-300 hover:text-red-500 transition-colors ml-1">
                    <X size={14}/>
                  </button>
                </div>
              ))}
            </div>
            <div className="flex gap-2 max-w-md">
              <input 
                type="text" 
                placeholder="New size label (e.g. 50, XXS)" 
                className="flex-1 border-2 border-slate-200 rounded-xl px-4 py-2 text-xs font-bold outline-none focus:border-indigo-500 transition-all bg-white text-slate-900"
                value={newSizeInput}
                onChange={e => setNewSizeInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), handleAddSize())}
              />
              <button 
                type="button" 
                onClick={handleAddSize}
                className="bg-indigo-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
              >
                Add Size
              </button>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Color & Size Matrix</label>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-x-auto bg-white shadow-lg">
              <table className="w-full text-center text-sm border-collapse min-w-full">
                <thead className="bg-slate-50 text-slate-400 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r sticky left-0 bg-slate-50 z-10">Color Variant</th>
                    {currentSizes.map(label => (
                      <th key={label} className="p-4 border-r min-w-[80px] bg-slate-50/50">{label}</th>
                    ))}
                    <th className="p-4 bg-slate-100 min-w-[100px]">Row Total</th>
                    <th className="p-4 w-12"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {breakdown.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-3 border-r sticky left-0 bg-white group-hover:bg-slate-50/50 z-10 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                        <input placeholder="e.g. Navy" className="w-full border-2 border-slate-50 rounded-xl px-4 py-3 bg-white focus:ring-2 focus:ring-indigo-500 font-bold outline-none text-slate-900" value={row.color} onChange={e => { const nb = [...breakdown]; nb[idx].color = e.target.value; setBreakdown(nb); }}/>
                      </td>
                      {currentSizes.map(label => (
                        <td key={label} className="p-3 border-r">
                          <input 
                            type="number" 
                            className="w-full border-2 border-slate-50 rounded-xl px-2 py-3 text-center bg-white focus:ring-2 focus:ring-indigo-500 font-black outline-none text-slate-900" 
                            value={row[label] || ''} 
                            onChange={e => { 
                              const nb = [...breakdown]; 
                              nb[idx][label] = parseInt(e.target.value) || 0; 
                              setBreakdown(nb); 
                            }}
                          />
                        </td>
                      ))}
                      <td className="p-3 font-black text-indigo-700 bg-slate-50/50 tabular-nums text-lg">{getBreakdownRowTotal(row, currentSizes)}</td>
                      <td className="p-3">
                        {breakdown.length > 1 && (
                          <button type="button" onClick={() => setBreakdown(breakdown.filter((_, i) => i !== idx))} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                            <Trash2 size={20}/>
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <button 
                type="button" 
                onClick={() => setBreakdown([...breakdown, { color: '' }])} 
                className="w-full py-5 text-[10px] font-black text-indigo-600 hover:bg-indigo-50 border-t border-slate-100 transition-colors bg-slate-50/20 uppercase tracking-widest flex items-center justify-center gap-2"
              >
                <PlusCircle size={16}/> Add New Color Row
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Production Notes</label><textarea className="w-full border-2 border-slate-100 rounded-3xl p-6 h-48 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-slate-900" value={newOrder.description} onChange={e => setNewOrder({...newOrder, description: e.target.value})} placeholder="Enter any specific manufacturing requirements or fabric details..."></textarea></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Technical Tech-Packs</label>
              <div className="border-4 border-dashed border-slate-100 rounded-3xl p-8 bg-slate-50 hover:bg-indigo-50/30 hover:border-indigo-200 relative h-48 flex flex-col items-center justify-center cursor-pointer transition-all">
                <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/>
                <Upload size={48} className="text-slate-300 mb-3" /><p className="text-base font-black text-slate-700 uppercase">Upload Reference Files</p>
              </div>
              <div className="mt-4 flex flex-wrap gap-2">{selectedFiles.map((f, i) => (<div key={i} className="flex items-center gap-2 bg-indigo-600 text-white px-3 py-1.5 rounded-lg text-xs font-black shadow-md"><ImageIcon size={14}/> {f.name} <button type="button" onClick={() => setSelectedFiles(prev => prev.filter((_, idx) => idx !== i))}><X size={14}/></button></div>))}</div>
            </div>
          </div>
          <div className="flex justify-end gap-4 pt-8 border-t">
            <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:bg-slate-100 rounded-2xl uppercase tracking-widest text-xs">Discard</button>
            <button type="submit" disabled={isUploading} className="px-12 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">
              {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Send size={18}/>} Launch to Units
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Pencil, Trash2, Printer, Save, Loader2, Clock, Paperclip, Box, Image as ImageIcon, FileText, Download, Upload, BookOpen, Calculator } from 'lucide-react';
import { Order, Unit, OrderLog, SizeBreakdown, Attachment, formatOrderNumber, Style, DetailedRequirement, getBreakdownRowTotal, getOrderSizeLabels } from '../../types';
import { fetchOrderLogs, updateOrderDetails, deleteOrder, triggerOrderEmail, uploadOrderAttachment, fetchStyleByNumber, fetchStyles, calculateOrderForecast } from '../../services/db';

interface AdminOrderDetailsModalProps {
  order: Order;
  units: Unit[];
  onClose: () => void;
  onRefresh: () => void;
}

export const AdminOrderDetailsModal: React.FC<AdminOrderDetailsModalProps> = ({ order, units, onClose, onRefresh }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editFormData, setEditFormData] = useState<Partial<Order>>({ ...order });
  const [modalLogs, setModalLogs] = useState<OrderLog[]>([]);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [availableStyles, setAvailableStyles] = useState<Style[]>([]);
  const [selectedStyleId, setSelectedStyleId] = useState<string>('');

  const sizeLabels = getOrderSizeLabels(editFormData);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getBreakdownRowTotal(row, sizeLabels), 0);

  useEffect(() => {
    fetchOrderLogs(order.id).then(setModalLogs);
    fetchStyles().then(setAvailableStyles);

    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
        fetchStyleByNumber(styleRefPart).then(s => {
            setLinkedStyle(s);
            if (s) setSelectedStyleId(s.id);
        });
    }
  }, [order.id, order.style_number]);

  const handleStyleSelect = (styleId: string) => {
    setSelectedStyleId(styleId);
    const style = availableStyles.find(s => s.id === styleId);
    if (!style) return;

    const newStyleNum = `${style.style_number} - ${style.style_text}`;
    setEditFormData(prev => ({ ...prev, style_number: newStyleNum }));
    setLinkedStyle(style);

    if (style.available_colors && style.available_colors.length > 0) {
      if (confirm("Would you like to reset the matrix based on the new style technical specs?")) {
        const newBreakdown = style.available_colors
          .filter(c => c.trim() !== '')
          .map(color => {
             const row: SizeBreakdown = { color };
             if (style.available_sizes) {
               style.available_sizes.forEach(sz => row[sz] = 0);
             }
             return row;
          });
        setEditFormData(prev => ({ ...prev, size_breakdown: newBreakdown }));
      }
    }
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (isEditing && linkedStyle) {
      return calculateOrderForecast({ ...order, ...editFormData } as Order, linkedStyle);
    }
    if (order.material_forecast && order.material_forecast.length > 0) {
      return order.material_forecast;
    }
    if (linkedStyle) {
      return calculateOrderForecast(order, linkedStyle);
    }
    return [];
  };

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const newAttachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) newAttachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }
      const finalAttachments = [...(editFormData.attachments || []), ...newAttachments];
      const finalQty = (editFormData.size_breakdown || []).reduce((acc, row) => acc + getBreakdownRowTotal(row, sizeLabels), 0);

      let finalForecast = order.material_forecast;
      if (linkedStyle) {
        finalForecast = calculateOrderForecast({ ...order, ...editFormData, quantity: finalQty } as Order, linkedStyle);
      }

      const result = await updateOrderDetails(order.id, { 
        ...editFormData, 
        quantity: finalQty, 
        attachments: finalAttachments, 
        material_forecast: finalForecast
      });

      if (result.success) {
        await triggerOrderEmail(order.id, true);
        onRefresh();
        onClose();
      } else {
        alert("Error saving: " + result.error);
      }
    } catch (err: any) {
        alert("Exception: " + err.message);
    } finally {
      setIsUploading(false);
    }
  };

  const handlePrint = async () => {
    const activeStyleNumber = isEditing ? editFormData.style_number : order.style_number;
    const formattedNo = formatOrderNumber(order);
    const headers = getOrderSizeLabels(editFormData);
    const activeBreakdown = (isEditing ? editFormData.size_breakdown : order.size_breakdown) || [];
    const breakdownRows = activeBreakdown.map(row => `<tr><td style="text-align:left; font-weight:bold; border: 1px solid #333;">${row.color}</td>${headers.map(h => `<td style="border: 1px solid #333;">${row[h] || 0}</td>`).join('')}<td style="font-weight:bold; background:#f1f5f9; border: 1px solid #333;">${getBreakdownRowTotal(row, headers)}</td></tr>`).join('');

    const win = window.open('', 'OrderPrint', 'width=1100,height=850');
    if (win) {
        win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title>
        <style>
          body { font-family: sans-serif; padding: 30px; color: #1e293b; font-size: 10px; line-height: 1.3; }
          .header { text-align: center; border-bottom: 3.5px solid #000; padding-bottom: 12px; margin-bottom: 18px; }
          .brand { font-size: 28px; font-weight: 900; }
          .grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-bottom: 15px; }
          .box { padding: 8px 12px; border: 1.5px solid #1e293b; border-radius:6px; }
          .label { font-size: 7px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-bottom:2px; display:block; }
          .value { font-size: 13px; font-weight: bold; }
          table { width: 100%; border-collapse: collapse; margin-top: 10px; }
          th, td { border: 1px solid #1e293b; padding: 6px; text-align: center; }
          th { background: #f8fafc; font-weight: bold; font-size: 8px; text-transform:uppercase; }
          .section-title { font-size: 12px; font-weight: 900; border-bottom: 1.5px solid #1e293b; margin-top: 20px; margin-bottom: 8px; text-transform: uppercase; padding-bottom:2px; }
          .notes-box { padding: 10px 15px; border: 1.5px solid #1e293b; background: #f8fafc; border-radius: 6px; font-size: 11px; font-weight:bold; white-space: pre-wrap; }
        </style>
        </head><body>
          <div class="header"><div class="brand">TINTURA SST</div><div>Manufacturing Job Execution</div></div>
          <div class="grid">
            <div class="box"><span class="label">Job ID</span><div class="value">${formattedNo}</div></div>
            <div class="box"><span class="label">Style</span><div class="value">${activeStyleNumber}</div></div>
            <div class="box"><span class="label">Batch Qty</span><div class="value">${isEditing ? (editFormData.quantity || 0) : order.quantity} PCS</div></div>
            <div class="box"><span class="label">Target Date</span><div class="value">${isEditing ? editFormData.target_delivery_date : order.target_delivery_date}</div></div>
          </div>
          <div class="section-title">Color & Size Matrix</div>
          <table><thead><tr><th style="text-align:left; border:1px solid #333;">Variant</th>${headers.map(h => `<th style="border:1px solid #333;">${h}</th>`).join('')}<th style="border: 1px solid #333;">Total</th></tr></thead><tbody>${breakdownRows}</tbody></table>
          <div class="section-title">Manufacturing Notes</div>
          <div class="notes-box">${isEditing ? editFormData.description : order.description || 'N/A'}</div>
          <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
        </body></html>`);
        win.document.close();
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-start bg-white">
          <div>
            <h3 className="text-3xl font-black text-slate-800 tracking-tight">{formatOrderNumber(order)}</h3>
            {isEditing && <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest mt-1">Editing Mode Active</p>}
          </div>
          <div className="flex items-center gap-3">
            {!isEditing && <button onClick={() => setIsEditing(true)} className="bg-indigo-50 text-indigo-700 border border-indigo-100 px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-600 hover:text-white transition-all"><Pencil size={18} /> Modify Order</button>}
            <button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full"><X size={32}/></button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">
          {isEditing && (
            <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100 animate-fade-in space-y-6">
              <div className="flex flex-col md:flex-row items-center gap-6">
                <div className="flex items-center gap-3 shrink-0">
                  <div className="p-3 bg-white rounded-xl text-indigo-600 shadow-sm border border-indigo-50"><BookOpen size={24}/></div>
                  <div>
                    <h4 className="font-black text-indigo-900 text-sm uppercase">Change Technical Style</h4>
                    <p className="text-indigo-400 text-[10px] font-bold uppercase tracking-widest mt-1">Relink to a different blueprint</p>
                  </div>
                </div>
                <div className="flex-1 w-full">
                  <select 
                    className="w-full bg-white border-2 border-indigo-200 rounded-xl px-5 py-4 text-sm font-black text-indigo-700 outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-sm"
                    value={selectedStyleId}
                    onChange={e => handleStyleSelect(e.target.value)}
                  >
                    <option value="">-- No linked style --</option>
                    {availableStyles.map(s => <option key={s.id} value={s.id}>{s.style_number} - {s.style_text}</option>)}
                  </select>
                </div>
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
                <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Reference Text</span>
                {isEditing ? <input className="w-full border rounded p-2 text-sm font-bold" value={editFormData.style_number} onChange={e => setEditFormData({...editFormData, style_number: e.target.value})}/> : <div className="text-sm font-black">{order.style_number}</div>}
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Volume</span>
              <div className="text-2xl font-black text-slate-800">{isEditing ? getTotalQuantity(editFormData.size_breakdown || []) : order.quantity} PCS</div>
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Delivery</span>
              {isEditing ? <input type="date" className="w-full border rounded p-2 font-bold" value={editFormData.target_delivery_date} onChange={e => setEditFormData({...editFormData, target_delivery_date: e.target.value})}/> : <div className="text-lg font-black">{order.target_delivery_date}</div>}
            </div>
            <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Facility Unit</span>
              {isEditing ? <select className="w-full border rounded p-2 bg-white font-bold" value={editFormData.unit_id} onChange={e => setEditFormData({...editFormData, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select> : <div className="text-lg font-black">{units.find(u => u.id === order.unit_id)?.name}</div>}
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>
              {isEditing && <button type="button" onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '' }]})} className="text-[10px] bg-indigo-600 text-white px-4 py-2 rounded-xl font-black uppercase">+ Add Color</button>}
            </div>
            <div className="border border-slate-200 rounded-3xl overflow-x-auto shadow-sm bg-white">
              <table className="w-full text-center text-sm border-collapse min-w-full">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] border-b">
                  <tr>
                    <th className="p-4 text-left border-r sticky left-0 bg-slate-50 z-10">Color Variant</th>
                    {sizeLabels.map(h => <th key={h} className="p-4 border-r min-w-[80px]">{h}</th>)}
                    <th className="p-4 bg-slate-100 min-w-[100px]">Sum</th>
                    {isEditing && <th className="p-4 w-12"></th>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50">
                      <td className="p-4 text-left font-black text-slate-700 border-r sticky left-0 bg-white z-10">
                        {isEditing ? <input className="w-full border rounded p-1 font-bold text-sm" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}
                      </td>
                      {sizeLabels.map(label => (
                        <td key={label} className="p-4 border-r">
                          {isEditing ? <input type="number" className="w-full border rounded p-1 text-center font-black" value={row[label] || ''} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx][label] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : (row[label] || 0)}
                        </td>
                      ))}
