import { supabase } from './supabase';
export { supabase };
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, Style, StyleTemplate, BulkEditHistory, formatOrderNumber, DetailedRequirement, ConsumptionType, getBreakdownRowTotal, getOrderSizeLabels, getQuantityForSize } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- Forecast Calculation Core Engine ---
export const calculateOrderForecast = (order: Order, style: Style): DetailedRequirement[] => {
  if (!style || !order.size_breakdown || order.size_breakdown.length === 0) return [];

  const detailedReqs: DetailedRequirement[] = [];
  const sizeLabels = getOrderSizeLabels(order);

  const calculateVal = (qty: number, type: ConsumptionType, val: number) => !val ? 0 : (type === 'items_per_pc' ? qty * val : qty / val);

  for (const catName in style.tech_pack) {
    for (const fieldName in style.tech_pack[catName]) {
      const item = style.tech_pack[catName][fieldName];
      const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

      if (item.variants) {
        for (const variant of item.variants) {
          const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
          if (matchingRows.length === 0) continue;

          if (variant.sizeVariants) {
            for (const sv of variant.sizeVariants) {
              const qty = matchingRows.reduce((sum, row) => sum + sv.sizes.reduce((s, label) => s + getQuantityForSize(row, label), 0), 0);

              if (qty > 0) {
                const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                const calc = calculateVal(qty, rType, rVal);

                req.breakdown.push({
                  label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                  count: qty,
                  calc: Math.ceil(calc * 100) / 100,
                  text: sv.text || variant.text || item.text,
                  attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                });
                req.total += calc;
              }
            }
          } else if (variant.consumption_type) {
            const qty = matchingRows.reduce((sum, row) => sum + getBreakdownRowTotal(row, sizeLabels), 0);
            const calc = calculateVal(qty, variant.consumption_type, variant.consumption_val || 0);
            req.breakdown.push({
              label: `Color: ${variant.colors.join('/')}`,
              count: qty,
              calc: Math.ceil(calc * 100) / 100,
              text: variant.text || item.text,
              attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
            });
            req.total += calc;
          }
        }
      } else if (item.consumption_type) {
        const calc = calculateVal(order.quantity, item.consumption_type, item.consumption_val || 0);
        req.breakdown.push({
          label: "Global Requirement",
          count: order.quantity,
          calc: Math.ceil(calc * 100) / 100,
          text: item.text,
          attachments: item.attachments
        });
        req.total = calc;
      }

      if (req.total > 0) {
        req.total = Math.ceil(req.total * 100) / 100;
        detailedReqs.push(req);
      }
    }
  }
  return detailedReqs;
};

// --- AUTH SERVICES ---
export const authenticateUser = async (username: string, pass: string): Promise<AppUser | null> => {
  const { data } = await supabase.from('app_users').select('*').eq('username', username).eq('password', pass).single();
  return data;
};

// --- ORDER SERVICES ---
export const fetchOrders = async (): Promise<Order[]> => {
  const { data } = await supabase.from('orders').select('*').order('created_at', { ascending: false });
  return data || [];
};

export const createOrder = async (order: Partial<Order>) => {
  return await supabase.from('orders').insert([order]).select().single();
};

export const updateOrderDetails = async (id: string, updates: Partial<Order>) => {
  const { error } = await supabase.from('orders').update(updates).eq('id', id);
  return { success: !error, error: error?.message };
};

export const deleteOrder = async (id: string) => {
  await supabase.from('orders').delete().eq('id', id);
};

export const updateOrderStatus = async (id: string, status: OrderStatus, message?: string, data?: any, attachmentUrl?: string) => {
  const updates: any = { status, ...data };
  if (attachmentUrl) updates.qc_attachment_url = attachmentUrl;
  await supabase.from('orders').update(updates).eq('id', id);
  if (message) await addOrderLog(id, 'STATUS_CHANGE', message);
};

export const fetchOrderLogs = async (orderId?: string): Promise<OrderLog[]> => {
  let query = supabase.from('order_logs').select('*').order('created_at', { ascending: false });
  if (orderId) query = query.eq('order_id', orderId);
  const { data } = await query;
  return data || [];
};

export const addOrderLog = async (orderId: string, logType: string, message: string) => {
  await supabase.from('order_logs').insert([{ order_id: orderId, log_type: logType, message }]);
};

export const triggerOrderEmail = async (orderId: string, isUpdate: boolean) => {
  const res = await fetch(`${API_BASE}/api/send-email`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ order_id: orderId, is_update: isUpdate })
  });
  return await res.json();
};

export const recordOrderEditHistory = async (description: string, snapshot: Order[]) => {
