  if (!history) return { success: false, error: "History not found" };
  for (const order of history.snapshot) {
    await supabase.from('orders').update(order).eq('id', order.id);
  }
  return { success: true };
};

// --- UNIT SERVICES ---
export const fetchUnits = async (): Promise<Unit[]> => {
  const { data } = await supabase.from('units').select('*');
  return data || [];
};

// --- STYLE SERVICES ---
export const fetchStyles = async (): Promise<Style[]> => {
  const { data } = await supabase.from('styles').select('*').order('style_number');
  return data || [];
};

export const fetchStyleByNumber = async (num: string): Promise<Style | null> => {
  const { data } = await supabase.from('styles').select('*').eq('style_number', num).single();
  return data;
};

export const fetchStyleTemplate = async (): Promise<StyleTemplate | null> => {
  const { data } = await supabase.from('style_templates').select('*').limit(1).single();
  return data;
};

export const upsertStyle = async (style: Partial<Style>) => {
  const { error } = await supabase.from('styles').upsert(style);
  return { error: error?.message };
};

export const deleteStyle = async (id: string) => {
  await supabase.from('styles').delete().eq('id', id);
};

export const recordBulkEditHistory = async (description: string, snapshot: Style[]) => {
  await supabase.from('bulk_edit_history').insert([{ description, affected_count: snapshot.length, snapshot }]);
};

export const fetchBulkEditHistory = async (): Promise<BulkEditHistory[]> => {
  const { data } = await supabase.from('bulk_edit_history').select('*').order('created_at', { ascending: false });
  return data || [];
};

export const undoBulkEdit = async (historyId: string) => {
  const { data: history } = await supabase.from('bulk_edit_history').select('*').eq('id', historyId).single();
  if (!history) return { success: false, error: "History not found" };
  for (const style of history.snapshot) {
    await supabase.from('styles').update(style).eq('id', style.id);
  }
  return { success: true };
};

export const syncAllOrdersWithStyles = async () => {
  const orders = await fetchOrders();
  const styles = await fetchStyles();
  let count = 0;
  for (const order of orders) {
    const styleRef = order.style_number.split(' - ')[0].trim();
    const style = styles.find(s => s.style_number === styleRef);
    if (style) {
      const forecast = calculateOrderForecast(order, style);
      await supabase.from('orders').update({ material_forecast: forecast }).eq('id', order.id);
      count++;
    }
  }
  return { updated: count };
};

// --- MATERIAL SERVICES ---
export const fetchMaterialRequests = async (): Promise<MaterialRequest[]> => {
  const { data } = await supabase.from('material_requests').select('*').order('created_at', { ascending: false });
  return data || [];
};

export const createMaterialRequest = async (req: Partial<MaterialRequest>) => {
  await supabase.from('material_requests').insert([req]);
};

export const updateMaterialRequest = async (id: string, updates: Partial<MaterialRequest>) => {
  await supabase.from('material_requests').update(updates).eq('id', id);
};

export const deleteMaterialRequest = async (id: string) => {
  await supabase.from('material_requests').delete().eq('id', id);
};

export const approveMaterialRequest = async (id: string, qty: number, currentApproved: number, status: MaterialStatus) => {
  await supabase.from('material_requests').update({ quantity_approved: currentApproved + qty, status }).eq('id', id);
  await supabase.from('material_approvals').insert([{ request_id: id, qty_approved: qty }]);
};

export const fetchMaterialApprovals = async (reqId: string): Promise<MaterialApproval[]> => {
  const { data } = await supabase.from('material_approvals').select('*').eq('request_id', reqId).order('created_at', { ascending: false });
