  });
  return await res.json();
};

// --- BARCODE & INVENTORY SERVICES ---
export const fetchBarcodes = async (status?: BarcodeStatus): Promise<Barcode[]> => {
  let query = supabase.from('barcodes').select('*');
  if (status) query = query.eq('status', status);
  const { data } = await query;
  return data || [];
};

export const fetchBarcodesBySerialList = async (serials: string[]): Promise<Barcode[]> => {
  const { data } = await supabase.from('barcodes').select('*').in('barcode_serial', serials);
  return data || [];
};

export const generateBarcodes = async (orderId: string, qty: number, style: string, size: string): Promise<Barcode[]> => {
  const { data: order } = await supabase.from('orders').select('last_barcode_serial').eq('id', orderId).single();
  let start = (order?.last_barcode_serial || 0) + 1;
  const newBarcodes = [];
  for (let i = 0; i < qty; i++) {
    const serial = `BC-${orderId.slice(0,4)}-${(start + i).toString().padStart(6, '0')}`;
    newBarcodes.push({ order_id: orderId, barcode_serial: serial, style_number: style, size, status: BarcodeStatus.GENERATED });
  }
  const { data } = await supabase.from('barcodes').insert(newBarcodes).select();
  await supabase.from('orders').update({ last_barcode_serial: start + qty - 1 }).eq('id', orderId);
  return data || [];
};

export const commitBarcodesToStock = async (serials: string[]) => {
  const { data: commit } = await supabase.from('stock_commits').insert([{ total_items: serials.length }]).select().single();
  if (commit) {
    await supabase.from('barcodes').update({ status: BarcodeStatus.COMMITTED_TO_STOCK, commit_id: commit.id }).in('barcode_serial', serials);
  }
};

export const fetchStockCommits = async (): Promise<StockCommit[]> => {
  const { data } = await supabase.from('stock_commits').select('*').order('created_at', { ascending: false });
