      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search by Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
          onPrintMaterials={() => handlePrintMaterialForecast(detailsModal)}
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, SizeBreakdown, Style, ConsumptionType, Attachment } from '../../types';
import { X, ImageIcon, FileText, Download, Paperclip, Printer, Box, Calculator } from 'lucide-react';
import { fetchStyleByNumber } from '../../services/db';

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

interface OrderDetailsModalProps {
  order: Order;
  useNumericSizes: boolean;
  onToggleSizeFormat: () => void;
  onClose: () => void;
  onPrint: () => void;
  onPrintMaterials: () => void;
}

export const OrderDetailsModal: React.FC<OrderDetailsModalProps> = ({
  order,
  useNumericSizes,
  onClose,
  onPrint,
  onPrintMaterials
}) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
      fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.style_number]);

  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  // Fix: cast to Number to resolve type mismatch
  const getRowTotal = (row: SizeBreakdown) => (Number(row.s) || 0) + (Number(row.m) || 0) + (Number(row.l) || 0) + (Number(row.xl) || 0) + (Number(row.xxl) || 0) + (Number(row.xxxl) || 0);

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                // Fix: cast to Number to resolve type mismatch
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (Number(row[k]) || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const renderDetailCell = (rowIdx: number, sizeKey: keyof SizeBreakdown) => {
    const plannedRow = order.size_breakdown?.[rowIdx];
    const actualRow = order.completion_breakdown?.[rowIdx];
    const plannedVal = plannedRow ? (Number(plannedRow[sizeKey]) || 0) : 0;

    if (order.status !== OrderStatus.COMPLETED || !actualRow) {
      return <span className="text-slate-600 font-medium">{plannedVal}</span>;
    }

    const actualVal = Number(actualRow[sizeKey]) || 0;
    const isMismatch = actualVal !== plannedVal;

    return (
      <div className="flex flex-col items-center justify-center p-1 bg-slate-50 rounded border border-slate-100">
        <span className={`text-lg font-black ${isMismatch ? 'text-indigo-700' : 'text-slate-900'}`}>
          {actualVal}
        </span>
        <span className="text-[10px] font-bold text-slate-400 border-t border-slate-200 w-full text-center mt-0.5 pt-0.5">
          Plan: {plannedVal}
        </span>
      </div>
    );
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden max-h-[95vh] flex flex-col animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{order.order_no}</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Production Execution Details</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={28} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Style Number</span>
              <span className="text-lg font-black text-slate-800">{order.style_number}</span>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Delivery Date</span>
              <span className="text-lg font-black text-slate-800">{order.target_delivery_date}</span>
            </div>
            <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
              <span className="block text-indigo-400 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Planned Boxes</span>
              <span className="text-xl font-black text-indigo-800">{order.box_count || '---'}</span>
            </div>
            {order.status === OrderStatus.COMPLETED && (
               <div className="p-4 bg-green-50 rounded-xl border border-green-100 shadow-sm animate-fade-in">
                <span className="block text-green-500 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Actual Packed</span>
                <span className="text-xl font-black text-green-800">{order.actual_box_count}</span>
              </div>
            )}
          </div>

          {/* DETAILED REQUIREMENTS SECTION */}
          {detailedReqs.length > 0 && (
            <div className="space-y-4 animate-fade-in">
              <div className="p-4 bg-indigo-600 text-white rounded-t-2xl flex items-center justify-between">
                <h4 className="font-black uppercase tracking-[0.1em] text-xs flex items-center gap-2"><Calculator size={16}/> Segmented Material Requirements</h4>
                <span className="text-[10px] font-bold opacity-70">SYNCED FROM MASTER TECH-PACK</span>
              </div>
              <div className="space-y-4">
                {detailedReqs.map((req, i) => (
                  <div key={i} className="bg-white rounded-2xl border border-indigo-100 overflow-hidden shadow-sm">
                    <div className="px-5 py-3 bg-indigo-50 border-b border-indigo-100 flex justify-between items-center">
                       <span className="font-black text-indigo-900 text-sm">{req.name}</span>
                       <span className="font-black text-indigo-700">Total: {req.total}</span>
                    </div>
                    <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                      {req.breakdown.map((b, idx) => (
                        <div key={idx} className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-2">
                           <div className="flex justify-between items-center">
                              <span className="text-[9px] font-black text-slate-500 uppercase">{b.label}</span>
                              <span className="text-sm font-black text-indigo-600">{b.calc} Req.</span>
                           </div>
                           <p className="text-xs text-slate-600 font-medium italic">"{b.text || 'No segments notes.'}"</p>
                           {b.attachments.length > 0 && (
                             <div className="flex flex-wrap gap-2 mt-2">
                                {b.attachments.map((att, attIdx) => (
                                  <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-white border rounded text-[9px] font-bold text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-all">
                                    {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                  </a>
                                ))}
                             </div>
                           )}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">
                Production Matrix
                {order.status === OrderStatus.COMPLETED && <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full ml-3 border border-indigo-100 uppercase tracking-widest">Actual / Planned</span>}
              </h4>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-hidden shadow-md">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r">Color Variant</th>
                    {getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}
                    <th className="p-4 font-black bg-slate-100">Row Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {order.size_breakdown?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-4 text-left font-black text-slate-700 border-r">{row.color}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 's')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'm')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'l')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxxl')}</td>
                      <td className="p-4 font-black bg-slate-50/50 text-slate-800 tabular-nums">{getRowTotal(row)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-slate-50/50 rounded-2xl border border-slate-200 shadow-inner">
              <h4 className="font-black text-slate-400 mb-4 uppercase tracking-widest text-[10px]">Production Instructions</h4>
              <p className="text-base text-slate-600 font-medium whitespace-pre-wrap leading-relaxed">{order.description || "No specific instructions provided."}</p>
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-2xl border border-indigo-100 shadow-inner">
              <h4 className="font-black text-indigo-400 mb-4 uppercase tracking-widest text-[10px] flex items-center gap-2">
                <Paperclip size={14}/> Technical Reference Files
              </h4>
              <div className="space-y-3">
                {order.attachments && order.attachments.length > 0 ? (
                  order.attachments.map((att, i) => (
                    <a key={i} href={att.url} target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 hover:shadow-lg transition-all group">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-100 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                          {att.type === 'image' ? <ImageIcon size={20} /> : <FileText size={20} />}
                        </div>
                        <span className="text-sm font-bold text-slate-700 truncate max-w-[200px]">{att.name}</span>
                      </div>
                      <Download size={18} className="text-slate-300 group-hover:text-indigo-600 transition-colors" />
                    </a>
                  ))
                ) : (
                  <div className="text-center py-10 text-slate-300">
                    <Paperclip size={32} className="mx-auto opacity-20 mb-2" />
                    <p className="text-[10px] uppercase font-black tracking-widest opacity-60">No documents attached</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
        <div className="p-6 border-t bg-slate-50 text-right flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.03)]">
          <button onClick={onPrintMaterials} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-200 rounded-xl font-bold hover:bg-indigo-50 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-[10px]">
            <Calculator size={16} /> Print Material Forecast
          </button>
          <div className="flex gap-4">
            <button onClick={onPrint} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-xs">
              <Printer size={18} /> Print Job Sheet
            </button>
            <button onClick={onClose} className="bg-slate-800 text-white px-10 py-3 rounded-xl font-black hover:bg-slate-700 transition-all active:scale-95 uppercase tracking-widest text-xs">Close</button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Order, MaterialRequest, SizeBreakdown, Style, ConsumptionType, Attachment } from '../../types';
import { X, Trash2, Calculator, ArrowLeftRight, Check, Plus, Paperclip, Files, Loader2, Zap, Info, ImageIcon, FileText } from 'lucide-react';
import { uploadOrderAttachment, createMaterialRequest, updateMaterialRequest, fetchStyleByNumber } from '../../services/db';

interface MaterialRow {
  id: number;
  name: string;
  qtyPerPc: number;
  targetPcs: number;
  targetLabel: string;
  requestQty: number;
  unit: string;
  files: File[];
}

interface ForecastedItem {
  id: string;
  name: string;
  label: string;
  calc: number;
  unit: string;
  text: string;
  attachments: Attachment[];
  isSelected: boolean;
}

interface MaterialRequestModalProps {
  orderId: string;
  orderNo: string;
  orders: Order[];
  onClose: () => void;
  isEditingRequest: { id: string; originalData: MaterialRequest } | null;
  useNumericSizes: boolean;
  onRefresh: () => void;
}

export const MaterialRequestModal: React.FC<MaterialRequestModalProps> = ({
  orderId,
  orderNo,
  orders,
  onClose,
  isEditingRequest,
  useNumericSizes,
  onRefresh
}) => {
  const order = orders.find(o => o.id === orderId);
  const initialQty = order ? order.quantity : 0;

  const [reqTab, setReqTab] = useState<'direct' | 'pcs' | 'forecast'>(isEditingRequest ? 'direct' : 'forecast');
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [isStyleLoading, setIsStyleLoading] = useState(false);

  const [materialRows, setMaterialRows] = useState<MaterialRow[]>(
    isEditingRequest 
      ? [{ id: 1, name: isEditingRequest.originalData.material_content, qtyPerPc: 0, targetPcs: 0, targetLabel: '', requestQty: isEditingRequest.originalData.quantity_requested, unit: isEditingRequest.originalData.unit, files: [] }]
      : [{ id: 1, name: '', qtyPerPc: 0, targetPcs: initialQty, targetLabel: `Full Order (${initialQty})`, requestQty: 0, unit: 'Nos', files: [] }]
  );

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [qtyFilterModal, setQtyFilterModal] = useState<{ isOpen: boolean, rowIndex: number | null }>({ isOpen: false, rowIndex: null });
  const [filterMode, setFilterMode] = useState<'matrix' | 'manual'>('matrix');
  const [selectedRows, setSelectedRows] = useState<number[]>([]);
  const [selectedCols, setSelectedCols] = useState<string[]>([]);
  const [manualOverrideQty, setManualOverrideQty] = useState<number>(0);

  // Forecast specific state
  const [forecastItems, setForecastItems] = useState<ForecastedItem[]>([]);

  // Fetch Style and calculate forecast
  useEffect(() => {
    if (order?.style_number) {
      setIsStyleLoading(true);
      const styleRefPart = order.style_number.split(' - ')[0].trim();
      fetchStyleByNumber(styleRefPart).then(s => {
        setLinkedStyle(s);
        setIsStyleLoading(false);
      });
    }
  }, [order?.style_number]);

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  // Fix: cast to Number to resolve type mismatch
  const getRowTotal = (row: SizeBreakdown) => (Number(row.s) || 0) + (Number(row.m) || 0) + (Number(row.l) || 0) + (Number(row.xl) || 0) + (Number(row.xxl) || 0) + (Number(row.xxxl) || 0);

  // Generate Forecast Items when linkedStyle or Order changes
  useEffect(() => {
    if (!linkedStyle || !order?.size_breakdown) return;

    const items: ForecastedItem[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                // Fix: cast to Number to resolve type mismatch
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (Number(row[k]) || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  items.push({
                    id: `${fieldName}-${variant.colors.join('')}-${sv.sizes.join('')}`,
                    name: fieldName,
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    calc: Math.ceil(calc * 100) / 100,
                    unit: 'Nos', // Default to Nos, can be enhanced to pull from techpack if added later
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments),
                    isSelected: false
                  });
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              items.push({
                id: `${fieldName}-${variant.colors.join('')}`,
                name: fieldName,
                label: `Color: ${variant.colors.join('/')}`,
                calc: Math.ceil(calc * 100) / 100,
                unit: 'Nos',
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments,
                isSelected: false
              });
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          items.push({
            id: `${fieldName}-global`,
            name: fieldName,
            label: "Global Requirement",
            calc: Math.ceil(calc * 100) / 100,
            unit: 'Nos',
            text: item.text,
            attachments: item.attachments,
            isSelected: false
          });
        }
      }
    }
    setForecastItems(items);
  }, [linkedStyle, order]);

  const handleRowChange = (id: number, field: keyof MaterialRow, value: any) => {
    setMaterialRows(prev => prev.map(row => row.id === id ? { ...row, [field]: value } : row));
  };

  const addRow = () => {
    setMaterialRows(prev => [...prev, { id: Date.now(), name: '', qtyPerPc: 0, targetPcs: initialQty, targetLabel: `Full Order (${initialQty})`, requestQty: 0, unit: 'Nos', files: [] }]);
  };

  const removeRow = (id: number) => {
    setMaterialRows(prev => prev.filter(row => row.id !== id));
  };

  const calculateSelection = () => {
    if (!order || !order.size_breakdown) return 0;
    let total = 0;
    order.size_breakdown.forEach((row, rIdx) => {
      const sizeKeys: (keyof SizeBreakdown)[] = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'];
      sizeKeys.forEach(key => {
        if (selectedRows.includes(rIdx) || selectedCols.includes(key)) {
          total += (Number(row[key]) || 0);
        }
      });
    });
    return total;
  };

  const handleConfirmQtyFilter = () => {
    if (qtyFilterModal.rowIndex === null) return;
    let finalQty = filterMode === 'manual' ? manualOverrideQty : calculateSelection();
    let label = filterMode === 'manual' ? `Manual (${finalQty})` : `Filter: ${selectedRows.length} Colors, ${selectedCols.length} Sizes`;
    const targetRowId = materialRows[qtyFilterModal.rowIndex].id;
    handleRowChange(targetRowId, 'targetPcs', finalQty);
    handleRowChange(targetRowId, 'targetLabel', label);
    setQtyFilterModal({ isOpen: false, rowIndex: null });
  };

  const toggleForecastSelection = (id: string) => {
    setForecastItems(prev => prev.map(item => item.id === id ? { ...item, isSelected: !item.isSelected } : item));
  };

  const handleSelectAllForecast = (select: boolean) => {
    setForecastItems(prev => prev.map(item => ({ ...item, isSelected: select })));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      if (reqTab === 'forecast') {
        const toSync = forecastItems.filter(i => i.isSelected);
        if (toSync.length === 0) {
          alert("No items selected for sync.");
          setIsSubmitting(false);
          return;
        }
        for (const item of toSync) {
          await createMaterialRequest({ 
            order_id: orderId, 
            material_content: `${item.name} (${item.label})`, 
            quantity_requested: item.calc, 
            unit: item.unit, 
            attachments: item.attachments as any 
          });
        }
      } else {
        for (const row of materialRows) {
          if (!row.name) continue;
          let finalQty = reqTab === 'direct' ? row.requestQty : (row.qtyPerPc * row.targetPcs);
          if (finalQty <= 0) continue;
          const attachments = [];
          for (const file of row.files) {
            const url = await uploadOrderAttachment(file);
            if (url) attachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
          }
          if (isEditingRequest) {
            await updateMaterialRequest(isEditingRequest.id, { material_content: row.name, quantity_requested: finalQty, unit: row.unit, attachments: attachments.length > 0 ? attachments as any : undefined });
          } else {
            await createMaterialRequest({ order_id: orderId, material_content: row.name, quantity_requested: finalQty, unit: row.unit, attachments: attachments as any });
          }
        }
      }
      onRefresh();
      onClose();
    } catch (err) {
      alert("Submission error. Check logs.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const matrixHeaders = useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const matrixKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'];

  return (
    <div className="fixed inset-0 bg-black/70 bg-opacity-50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col max-h-[90vh] animate-scale-up">
        <div className="p-6 border-b flex justify-between items-center bg-gradient-to-r from-blue-600 to-indigo-700 text-white">
          <div>
            <h3 className="text-2xl font-black flex items-center gap-2">
              <Calculator size={28}/> Accessories Requisition
            </h3>
            <p className="text-blue-100 text-sm font-bold opacity-80 mt-1 uppercase tracking-widest">Order: {orderNo}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={28} /></button>
        </div>

        <div className="p-8 space-y-6 overflow-y-auto flex-1 bg-slate-50/50">
          <div className="flex bg-slate-200 p-1.5 rounded-xl w-fit shadow-inner">
            <button 
              onClick={() => setReqTab('forecast')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'forecast' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Zap size={16}/> Forecast Sync
            </button>
            <button 
              onClick={() => setReqTab('pcs')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'pcs' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Calculator size={16}/> Calculator Mode
            </button>
            <button 
              onClick={() => setReqTab('direct')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'direct' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Files size={16}/> Direct Entry
            </button>
          </div>

          {reqTab === 'forecast' ? (
            <div className="space-y-4 animate-fade-in">
              <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-4 flex items-center gap-3">
                 <Info className="text-indigo-500" size={20}/>
                 <p className="text-xs font-bold text-indigo-800">Below are requirements pre-calculated from the technical blueprint linked to this style. Select items to push them to the Materials Requisition queue.</p>
              </div>

              {isStyleLoading ? (
                <div className="py-20 text-center flex flex-col items-center">
                   <Loader2 size={40} className="animate-spin text-indigo-600 mb-4"/>
                   <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Syncing with Style Database...</p>
                </div>
              ) : !linkedStyle ? (
                <div className="py-20 text-center bg-white border border-dashed rounded-3xl">
                   <X size={48} className="mx-auto text-slate-200 mb-2"/>
                   <p className="text-slate-400 font-bold">No technical blueprint found for this style.</p>
                   <p className="text-xs text-slate-300 mt-1">Please ensure the style exists in the Style DB to use Forecast Sync.</p>
                </div>
              ) : forecastItems.length === 0 ? (
                <div className="py-20 text-center bg-white border border-dashed rounded-3xl">
                   <Zap size={48} className="mx-auto text-slate-200 mb-2"/>
                   <p className="text-slate-400 font-bold">No forecasted material items found in the blueprint.</p>
                </div>
              ) : (
                <div className="bg-white rounded-2xl border border-slate-200 shadow-xl overflow-hidden">
                  <div className="p-4 bg-slate-50 border-b flex justify-between items-center">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Forecast Analysis</span>
                    <div className="flex gap-2">
                       <button onClick={() => handleSelectAllForecast(true)} className="text-[9px] font-black text-indigo-600 hover:underline uppercase">Select All</button>
                       <button onClick={() => handleSelectAllForecast(false)} className="text-[9px] font-black text-slate-400 hover:underline uppercase">Clear All</button>
                    </div>
                  </div>
                  <table className="w-full text-sm text-left">
                    <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                      <tr>
                        <th className="p-4 w-12"></th>
                        <th className="p-4">Material / Item</th>
                        <th className="p-4">Scope / Variant</th>
                        <th className="p-4 text-center">Calculated Req.</th>
                        <th className="p-4">Reference Docs</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {forecastItems.map((item) => (
                        <tr key={item.id} className={`group hover:bg-slate-50/80 transition-colors cursor-pointer ${item.isSelected ? 'bg-indigo-50/50' : ''}`} onClick={() => toggleForecastSelection(item.id)}>
                          <td className="p-4" onClick={e => e.stopPropagation()}>
                            <input 
                              type="checkbox" 
                              checked={item.isSelected} 
                              onChange={() => toggleForecastSelection(item.id)}
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                            />
                          </td>
                          <td className="p-4">
                            <span className="font-black text-slate-800">{item.name}</span>
                          </td>
                          <td className="p-4">
                            <span className="text-[10px] font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded-full uppercase tracking-tighter">{item.label}</span>
                          </td>
                          <td className="p-4 text-center">
                            <span className="font-black text-indigo-600 text-lg">{item.calc}</span>
                          </td>
                          <td className="p-4">
                            <div className="flex flex-wrap gap-1.5">
                              {item.attachments.map((att, idx) => (
                                <a 
                                  key={idx} 
                                  href={att.url} 
                                  target="_blank" 
                                  rel="noreferrer" 
                                  className="p-1.5 bg-slate-100 hover:bg-indigo-100 rounded border border-slate-200 hover:border-indigo-300 transition-all shadow-sm flex items-center justify-center group/icon" 
                                  title={att.name}
                                  onClick={e => e.stopPropagation()}
                                >
                                  {att.type === 'image' ? <ImageIcon size={14} className="text-slate-400 group-hover/icon:text-indigo-600 transition-colors"/> : <FileText size={14} className="text-slate-400 group-hover/icon:text-indigo-600 transition-colors"/>}
                                </a>
                              ))}
                              {item.attachments.length === 0 && <span className="text-[10px] text-slate-300 italic">None</span>}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          ) : (
            <div className="bg-white rounded-2xl border border-slate-200 shadow-xl overflow-hidden animate-fade-in">
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-5">Material Item</th>
                    {reqTab === 'pcs' && (
                      <>
                        <th className="p-5 text-center">Qty Per Pc</th>
                        <th className="p-5 text-center">Calculated For</th>
                      </>
                    )}
                    <th className="p-5 text-center">Total Required</th>
                    <th className="p-5 text-center">Unit</th>
                    <th className="p-5">Reference Files</th>
                    <th className="p-5 w-12"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {materialRows.map((row, rIdx) => (
                    <tr key={row.id} className="group hover:bg-slate-50/50 transition-colors">
                      <td className="p-4">
                        <input 
                          className="w-full border border-slate-200 rounded-xl px-4 py-3 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 shadow-sm outline-none" 
                          placeholder="e.g. Zippers, Buttons, Thread"
                          value={row.name} 
                          onChange={e => handleRowChange(row.id, 'name', e.target.value)} 
                        />
                      </td>
                      {reqTab === 'pcs' && (
                        <>
                          <td className="p-4 w-32">
                            <input 
                              type="number" 
                              step="any" 
                              className="w-full border border-slate-200 rounded-xl px-3 py-3 bg-white text-slate-900 text-center font-black focus:ring-2 focus:ring-indigo-500 shadow-sm outline-none" 
                              value={row.qtyPerPc} 
                              onChange={e => handleRowChange(row.id, 'qtyPerPc', parseFloat(e.target.value) || 0)} 
                            />
                          </td>
                          <td className="p-4">
                            <button 
                              type="button" 
                              onClick={() => setQtyFilterModal({ isOpen: true, rowIndex: rIdx })} 
                              className="w-full bg-indigo-50 hover:bg-indigo-100 border border-indigo-100 text-indigo-700 px-4 py-3 rounded-xl font-bold text-xs flex items-center justify-between transition-all"
                            >
                              <span className="truncate max-w-[120px]">{row.targetLabel}</span>
                              <ArrowLeftRight size={14} className="opacity-50"/>
                            </button>
                          </td>
                        </>
                      )}
                      <td className="p-4 w-32 text-center">
                        {reqTab === 'pcs' ? (
                          <div className="bg-slate-100 py-3 rounded-xl font-black text-lg text-indigo-700 shadow-inner">
                            {(row.qtyPerPc * row.targetPcs).toFixed(1)}
                          </div>
                        ) : (
                          <input 
                            type="number" 
                            className="w-full border border-slate-200 rounded-xl px-2 py-3 text-center bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 shadow-sm" 
                            value={row.requestQty} 
                            onChange={e => handleRowChange(row.id, 'requestQty', parseFloat(e.target.value) || 0)} 
                          />
                        )}
                      </td>
                      <td className="p-4 w-28">
                        <select 
                          className="w-full border border-slate-200 rounded-xl px-2 py-3 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 shadow-sm outline-none" 
                          value={row.unit} 
                          onChange={e => handleRowChange(row.id, 'unit', e.target.value)}
                        >
                          <option value="Nos">Nos</option>
                          <option value="Meters">Meters</option>
                          <option value="Kgs">Kgs</option>
                          <option value="Rolls">Rolls</option>
                        </select>
                      </td>
                      <td className="p-4">
                        <label className="flex items-center gap-2 cursor-pointer group/file">
                          <div className="p-3 bg-slate-100 group-hover/file:bg-indigo-100 text-slate-400 group-hover/file:text-indigo-600 rounded-xl transition-all">
                            <Paperclip size={18}/>
                          </div>
                          <input 
                            type="file" 
                            multiple 
                            className="hidden" 
                            onChange={e => handleRowChange(row.id, 'files', e.target.files ? Array.from(e.target.files) : [])} 
                          />
                          <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                               {row.files.length > 0 ? `${row.files.length} Files` : 'Upload'}
                             </span>
                             {row.files.length > 0 && <span className="text-[10px] text-indigo-500 font-bold truncate max-w-[80px]">{row.files[0].name}</span>}
                          </div>
                        </label>
                      </td>
                      <td className="p-4">
                        {materialRows.length > 1 && (
                          <button 
                            type="button" 
                            onClick={() => removeRow(row.id)}
                            className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                          >
                            <Trash2 size={20} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <button 
                type="button" 
                onClick={addRow} 
                className="w-full py-5 text-sm font-black text-indigo-600 hover:bg-indigo-50 border-t border-slate-100 flex items-center justify-center gap-2 transition-colors uppercase tracking-widest"
              >
                <Plus size={18}/> Add Line Item
              </button>
            </div>
          )}
        </div>

        <div className="p-6 border-t bg-slate-50 flex justify-end gap-4 shadow-inner">
          <button 
            type="button" 
            onClick={onClose} 
            className="px-8 py-3 font-bold text-slate-500 hover:bg-slate-100 rounded-xl transition-colors uppercase tracking-widest text-xs"
          >
            Discard
          </button>
          <button 
            type="button" 
            onClick={handleSubmit} 
            disabled={isSubmitting || isStyleLoading} 
            className="bg-indigo-600 text-white px-12 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 disabled:opacity-50 transition-all active:scale-95 flex items-center gap-2 uppercase tracking-widest text-xs"
          >
            {isSubmitting ? <><Loader2 size={20} className="animate-spin" /> Processing...</> : <><Check size={20}/> {reqTab === 'forecast' ? 'Sync Forecast to Materials' : 'Confirm Requisition'}</>}
          </button>
        </div>
      </div>

      {/* QUANTITY FILTER SUB-MODAL */}
      {qtyFilterModal.isOpen && (
        <div className="fixed inset-0 bg-slate-900/80 z-[60] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col animate-scale-up border border-slate-200">
            <div className="p-6 border-b bg-indigo-50 flex justify-between items-center">
              <div>
                <h4 className="font-black text-indigo-900 text-lg uppercase tracking-tight">Define Calculation Scope</h4>
                <p className="text-indigo-500 text-xs font-bold uppercase tracking-widest mt-0.5">Pick specific Colors or Sizes from Order Breakdown</p>
              </div>
              <button type="button" onClick={() => setQtyFilterModal({ isOpen: false, rowIndex: null })} className="text-indigo-400 hover:text-indigo-600 p-2"><X size={24}/></button>
            </div>

            <div className="p-8 space-y-8">
              <div className="flex gap-2 p-1.5 bg-slate-100 rounded-2xl w-fit shadow-inner">
                <button 
                  type="button" 
                  onClick={() => setFilterMode('matrix')} 
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${filterMode === 'matrix' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}
                >
                  Matrix Filter
                </button>
                <button 
                  type="button" 
                  onClick={() => setFilterMode('manual')} 
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${filterMode === 'manual' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}
                >
                  Manual Input
                </button>
              </div>

              {filterMode === 'matrix' ? (
                <div className="space-y-4">
                  <div className="border border-slate-200 rounded-2xl overflow-hidden shadow-sm">
                    <div className="overflow-x-auto">
                      <table className="w-full text-xs text-center border-collapse">
                        <thead className="bg-slate-50 text-slate-400 font-black uppercase tracking-tighter">
                          <tr>
                            <th className="p-3 border-r w-12"><Check size={14} className="mx-auto"/></th>
                            <th className="p-3 border-r text-left w-32">Variant</th>
                            {matrixHeaders.map((h, i) => (
                              <th 
                                key={h} 
                                className={`p-3 cursor-pointer border-r hover:bg-indigo-100 transition-colors ${selectedCols.includes(matrixKeys[i]) ? 'bg-indigo-600 text-white' : ''}`} 
                                onClick={() => {
                                  const key = matrixKeys[i];
                                  setSelectedCols(prev => prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]);
                                }}
                              >
                                {h}
                              </th>
                            ))}
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                          {order?.size_breakdown?.map((row, idx) => (
                            <tr key={idx} className={`${selectedRows.includes(idx) ? 'bg-indigo-50/50' : 'hover:bg-slate-50'}`}>
                              <td className="p-3 border-r">
                                <input 
                                  type="checkbox" 
                                  className="w-4 h-4 rounded text-indigo-600"
                                  checked={selectedRows.includes(idx)} 
                                  onChange={() => setSelectedRows(prev => prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx])} 
                                />
                              </td>
                              <td className={`p-3 text-left font-black border-r ${selectedRows.includes(idx) ? 'text-indigo-700' : 'text-slate-700'}`}>
                                {row.color}
                              </td>
                              {matrixKeys.map(key => {
                                const isHighlighted = selectedRows.includes(idx) || selectedCols.includes(key);
                                return (
                                  <td key={key} className={`p-3 border-r tabular-nums font-bold ${isHighlighted ? 'text-indigo-600 bg-indigo-50/30' : 'text-slate-300 font-medium'}`}>
                                    {/* Fix: cast to Number to resolve type mismatch */}
                                    {(Number((row as any)[key]) || 0)}
                                  </td>
                                );
                              })}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>

                  <div className="p-6 bg-gradient-to-br from-indigo-600 to-blue-700 rounded-2xl shadow-lg flex justify-between items-center text-white">
                    <div>
                      <span className="text-[10px] font-black uppercase tracking-widest opacity-70">Calculated Volume</span>
                      <h5 className="text-3xl font-black">{calculateSelection()} <span className="text-base opacity-70">Pieces</span></h5>
                    </div>
                    <div className="bg-white/20 p-3 rounded-xl border border-white/10 backdrop-blur-sm">
                       <Calculator size={32}/>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Total Target Pieces (Direct Count)</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      className="w-full border-2 border-slate-100 rounded-3xl p-8 text-6xl font-black bg-white text-indigo-600 focus:border-indigo-500 shadow-inner outline-none transition-all" 
                      value={manualOverrideQty} 
                      onChange={e => setManualOverrideQty(parseInt(e.target.value) || 0)} 
                    />
                    <div className="absolute right-8 top-1/2 -translate-y-1/2 text-slate-300">
                      <Calculator size={48} />
                    </div>
                  </div>
                  <p className="text-xs text-slate-400 italic text-center">Use this for manual overrides where matrix breakdown is unavailable.</p>
                </div>
              )}
            </div>

            <div className="p-6 border-t bg-slate-50 flex justify-end gap-3">
              <button 
                type="button" 
                onClick={() => setQtyFilterModal({ isOpen: false, rowIndex: null })} 
                className="px-6 py-3 font-bold text-slate-500 hover:bg-slate-200 rounded-xl transition-colors"
              >
                Cancel
              </button>
              <button 
                type="button" 
                onClick={handleConfirmQtyFilter} 
                className="px-10 py-3 bg-indigo-600 text-white rounded-xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
              >
                Apply Selection
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
